var gen_ch_11_Verses = [
  {num:1,words:[["Sa tasi lava le gagana e tasi foi le tautala a le lalolagi uma.", "And the whole earth was of one language, and of one speech."]]},
  {num:2,words:[["Ua oo foi iua latou o mai mai sasae,", "And it came to pass,"], ["ona maua lea e i latou le fanua laugatasi i le nuu o Senara,", "as they journeyed from the east, that they found a plain in the land of Shinar;"], ["ona latou mau ai lea.", "and they dwelt there."]]},
  {num:3,words:[["Ona latou fetautalatalai lea o le tasi ma le tasi,", "And they said one to another,"], ["Sau ia,", "Go to,"], ["ina tatoa faia ia o maaomea,", "let us make brick,"], ["ma matuā tunu ai i le afi. Ona fai loa o maaomea mo latou maa,", "and burn them throughly. And they had brick for stone,"], ["ua fai foi le pulu emeri mo latou panisina.", "and slime had they for morter."]]},
  {num:4,words:[["Ona latou fai aue lea,", "And they said,"], ["O mai ia, ina tatou fai ia o se aai,", "Go to,"], ["ma se 'olo,", "let us build us a city and a tower,"], ["ia oo lona tumutumu i le lagi,", "whose top may reach unto heaven;"], ["ia tatou faia foi se mea e ta'ua ai i tatou, ne'i faataapeapeina,", "and let us make us a name,"], ["i tatou i le fogāeleele uma.", "lest we be scattered abroad upon the face of the whole earth."]]},
  {num:5,words:[["Ona afio ifo lea o Ieova e silasila i le aai ma le 'olo ua faia e tagata.", "And the LORD came down to see the city and the tower, which the children of men builded."]]},
  {num:6,words:[["Ona fetalai ane lea o Ieova,", "And the LORD said,"], ["Faauta,", "Behold,"], ["ua tasi le nuu,", "the people is one,"], ["e tasi foi le gagana ia te i latou uma;", "and they have all one language;"], ["ua amata foi i latou ona fai o lenei mea;", "and this they begin to do:"], ["o lenei foi,", "and now nothing will be restrained from them,"], ["e le toe taofia i latou i se mea e tasi ua latou manatu i ai e fai.", "which they have imagined to do."]]},
  {num:7,words:[["O mai ia,", "Go to,"], ["ina tatou o ifo ia,", "let us go down,"], ["ma ia tatou faaeseeseina i lea mea a latou gagana,", "and there confound their language,"], ["ina ia le lagona e le tasi i le gagana a le tasi.", "that they may not understand one another's speech."]]},
  {num:8,words:[["Ona faataapeape lea e Ieova ia te i latou ai lea mea i le lalolagi uma;", "So the LORD scattered them abroad from thence upon the face of all the earth:"], ["ona tuua lea e i latou ona faia o le aai.", "and they left off to build the city."]]},
  {num:9,words:[["O le mea lea ua igoa ai ia o Papelu;", "Therefore is the name of it called Babel;"], ["auā na faaeseeseina i lea mea e Ieova o le gagana a le lalolagi uma;", "because the LORD did there confound the language of all the earth:"], ["na faataapeape foi e Ieova ia te i latou ai lea mea i le lalolagi uma.", "and from thence did the LORD scatter them abroad upon the face of all the earth."]]},
  {num:10,words:[["O le gafa lenei o Semu;", "These are the generations of Shem:"], ["na ola Semu i tausaga e selau,", "Shem was an hundred years old,"], ["ona fanaua lea e ia o Afasata i le lua o tausaga talu mai le lolo;", "and begat Arphaxad two years after the flood:"]]},
  {num:11,words:[["ona ola lea o Semu talu ina fanauina e ia o Afasata i tausaga e lima selau,", "And Shem lived after he begat Arphaxad five hundred years,"], ["ma ua fanaua ai e ia o atalii ma afafine.", "and begat sons and daughters."]]},
  {num:12,words:[["Na ola Afasata i tausaga e tolugafulu ma le lima,", "And Arphaxad lived five and thirty years,"], ["ona fanaua lea e ia o Selaa;", "and begat Salah:"]]},
  {num:13,words:[["ona ola lea o Afasata talu ina fanauina e ia o Selaa i tausaga e fa selau ma le tolu,", "And Arphaxad lived after he begat Salah four hundred and three years,"], ["ma ua fanaua ai e ia o atalii ma afafine.", "and begat sons and daughters."]]},
  {num:14,words:[["Na ola Selaa i tausaga e tolugafulu,", "And Salah lived thirty years,"], ["ona fanaua lea e ia o Eperu;", "and begat Eber:"]]},
  {num:15,words:[["ona ola lea o Salaa talu ina fanauina e ia o Eperu i tausaga e fa selau ma le tolu,", "And Salah lived after he begat Eber four hundred and three years,"], ["ma ua fanaua ai e ia o atalii ma afafine.", "and begat sons and daughters."]]},
  {num:16,words:[["Na ola Eperu i tausaga e tolugafulu ma le fa,", "And Eber lived four and thirty years,"], ["ona fanaua lea e ia o Peleko;", "and begat Peleg:"]]},
  {num:17,words:[["ona ola lea o Eperu talu ina fanauina e ia o Peleko i tausaga e fa selau ma le tolugafulu,", "And Eber lived after he begat Peleg four hundred and thirty years,"], ["ma ua fanaua ai e ia o atalii ma afafine.", "and begat sons and daughters."]]},
  {num:18,words:[["Na ola Peleko i tausaga e tolugafulu,", "And Peleg lived thirty years,"], ["ona fanaua lea e ia o Reu;", "and begat Reu:"]]},
  {num:19,words:[["ona ola lea o Peleko talu ina fanauina e ia o Reu i tausaga e lua selau ma le iya,", "And Peleg lived after he begat Reu two hundred and nine years,"], ["ma ua fanaua ai e ia o atalii ma afafine.", "and begat sons and daughters."]]},
  {num:20,words:[["Na ola Reu i tausaga e tolugafulu ma le lua,", "And Reu lived two and thirty years,"], ["ona fanaua lea e ia o Seruka;", "and begat Serug:"]]},
  {num:21,words:[["ona ola lea o Reu talu ina fanauina e ia o Seruka i tausaga e lua selau ma le fitu,", "And Reu lived after he begat Serug two hundred and seven years,"], ["ma ua fanaua ai e ia o atalii ma afafine.", "and begat sons and daughters."]]},
  {num:22,words:[["Na ola Seruka i tausaga e tolugafulu,", "And Serug lived thirty years,"], ["ona fanaua lea e ia o Nakori;", "and begat Nahor:"]]},
  {num:23,words:[["ona ola lea o Seruka talu ina fanauina e ia o Nakori i tausaga e lua selau,", "And Serug lived after he begat Nahor two hundred years,"], ["ma ua fanaua ai e ia o atalii ma afafine.", "and begat sons and daughters."]]},
  {num:24,words:[["Na ola Nakori i tausaga e lua sefulu ma le iva,", "And Nahor lived nine and twenty years,"], ["ona fanaua lea e ia o Tara;", "and begat Terah:"]]},
  {num:25,words:[["ona ola lea o Nakori talu ina fanauina e ia o Tara i tausaga e selau ma le sefulu ma le iva,", "And Nahor lived after he begat Terah an hundred and nineteen years,"], ["ma ua fanaua ai e ia o atalii ma afafine.", "and begat sons and daughters."]]},
  {num:26,words:[["Na ola Tara i tausaga e fitugafulu,", "And Terah lived seventy years,"], ["ona fanaua lea e ia o Aperamo,", "and begat Abram,"], ["ma Nakori,", "Nahor,"], ["ma Arana.", "and Haran."]]},
  {num:27,words:[["O gafa foi nei o Tara;", "Now these are the generations of Terah:"], ["na fanaua e Tara o Aperamo,", "Terah begat Abram,"], ["o Nakori ma Arana;", "Nahor, and Haran;"], ["na fanaua foi e Arana o Lota.", "and Haran begat Lot."]]},
  {num:28,words:[["Ua oti foi Arana, a o nofo mai lona tama o Tara,", "And Haran died before his father Terah in the land of his nativity,"], ["i le nuu na fanau ai o ia, o Uro lea i Kaletaia.", "in Ur of the Chaldees."]]},
  {num:29,words:[["Ona fai avā lea o i laua o Aperamo ma Nakori;", "And Abram and Nahor took them wives:"], ["o le igoa o le avā a Aperamo o Sarai lea;", "the name of Abram's wife was Sarai;"], ["a o le igoa o le avā a Nakori o Meleka,", "and the name of Nahor's wife, Milcah,"], ["o le afafine o Arana,", "the daughter of Haran,"], ["o le tamā o ia o Meleka,", "the father of Milcah,"], ["o le tamā foi o Iseka.", "and the father of Iscah."]]},
  {num:30,words:[["O Sarai foi ua pa ia,", "But Sarai was barren;"], ["ua leai sana tama.", "she had no child."]]},
  {num:31,words:[["Na ave foi e Tara lona atalii o Aperamo,", "And Terah took Abram his son,"], ["ma Lota le atalii o Arana,", "and Lot the son of Haran his son's son,"], ["o le atalii lea o lona atalii,", "and Sarai his daughter in law,"], ["o Sarai foi le avā a lona atalii,", "his son Abram's wife;"], ["o le avā lea a lona atalii o Aperamo;", "and they went forth with them from Ur of the Chaldees,"], ["ona latou o atu lea ma i latou ai Uro i Kaletaia,", "to go into the land of Canaan;"], ["o le a o atu i le nuu o Kanana;", "and they came unto Haran,"], ["ona latou oo lea i Karana ma nonofo ai.", "and dwelt there."]]},
  {num:32,words:[["O aso foi o Tara e lua selau ma le lima, o ona tausaga ia;", "And the days of Terah were two hundred and five years:"], ["ona oti lea o Tara i Karana.", "and Terah died in Haran."]]},
];
renderVerseSet(gen_ch_11_Verses, 'gen-ch11-verses');

var gen_ch_12_Verses = [
  {num:1,words:[["Ua fetalai mai Ieova ia Aperamo,", "Now the LORD had said unto Abram,"], ["Ia tuua e oe o lou nuu,", "Get thee out of thy country,"], ["ma tagata o lou nuu,", "and from thy kindred,"], ["ma le aiga o lou tamā,", "and from thy father's house,"], ["a e alu atu i se nuu ou te faasino atu ai ia te oe.", "unto a land that I will shew thee:"]]},
  {num:2,words:[["Ou te faia oe ma nuu tele,", "And I will make of thee a great nation,"], ["cu te faamanuia foi ia te oe,", "and I will bless thee,"], ["ou te matuā faamamaluina lou igoa;", "and make thy name great;"], ["e manuia foi oe.", "and thou shalt be a blessing:"]]},
  {num:3,words:[["Ou te faamanuia atu ia te i latou o e faamanuia ia te oe,", "And I will bless them that bless thee,"], ["ou te faamalaia atu foi ia te i latou o e fetuu ia te oe;", "and curse him that curseth thee:"], ["e manuia foi ia te oe o aiga uma o le lalolagi.", "and in thee shall all families of the earth be blessed."]]},
  {num:4,words:[["Ona alu ai lea o Aperamo e faapei ona fetalai mai o Ieova ia te ia;", "So Abram departed,"], ["na la o foi ma Lota;", "as the LORD had spoken unto him; and Lot went with him:"], ["na alu atu Aperamo nai Karana i lona tausaga e fitugafulu ma le lima.", "and Abram was seventy and five years old when he departed out of Haran."]]},
  {num:5,words:[["Ua ave foi e Aperamo lana avā o Sarai,", "And Abram took Sarai his wife,"], ["ma Lota le atalii o lona uso,", "and Lot his brother's son,"], ["ma o latou oloa uma lava na latou maua,", "and all their substance that they had gathered,"], ["ma tagata na latou maua i Karana;", "and the souls that they had gotten in Haran;"], ["ona latou o atu lea o le a o i le nuu o Kanana;", "and they went forth to go into the land of Canaan;"], ["ua oo foi i latou i le nuu o Kanana.", "and into the land of Canaan they came."]]},
  {num:6,words:[["Ua ui atu foi Aperamo i lea nuu ua oo i le mea e i ai Sekema,", "And Abram passed through the land unto the place of Sichem,"], ["i le aluna o Morē. Sa i ai sa Kananā i lea nuu i ia ona po.", "unto the plain of Moreh. And the Canaanite was then in the land."]]},
  {num:7,words:[["Ua faaali mai Ieova ia Aperamo,", "And the LORD appeared unto Abram,"], ["ma ua faapea mai,", "and said,"], ["Ou te foaiina atu lenei lava nuu mo lau fanau;", "Unto thy seed will I give this land:"], ["ona faia lea e ia i lea mea o le fata faitaulaga ia Ieova,", "and there builded he an altar unto the LORD,"], ["sa faaali mai o ia ia te ia.", "who appeared unto him."]]},
  {num:8,words:[["Ua tuua foi e ia lea mea,", "And he removed from thence unto a mountain on the east of Beth-el,"], ["a e alu atu i le mauga i le itu i sasae o Peteli,", "and pitched his tent,"], ["ma faatu ai lona fale ie, e i lona itu i sisifo o Peteli,", "having Beth-el on the west,"], ["a e i lona itu i sasae o Ai;", "and Hai on the east:"], ["ua ia faia foi le fata faitaulaga ia Ieova i lea mea,", "and there he builded an altar unto the LORD,"], ["ma ua valaau atu i le suafa o Ieova.", "and called upon the name of the LORD."]]},
  {num:9,words:[["Ua aga atu Aperamo,", "And Abram journeyed,"], ["ma alu atu pea i le itu i toga.", "going on still toward the south."]]},
  {num:10,words:[["Sa i ai foi le oge i lea nuu;", "And there was a famine in the land:"], ["ona alu ifo lea o Aperamo i Aikupito e āumau ai;", "and Abram went down into Egypt to sojourn there;"], ["auā sa vale le oge i le nuu.", "for the famine was grievous in the land."]]},
  {num:11,words:[["Ua latalata ina oo i Aikupito,", "And it came to pass,"], ["ona fai atu lea o ia i lana avā o Sarai,", "when he was come near to enter into Egypt,"], ["Faauta mai ea,", "that he said unto Sarai his wife, Behold now,"], ["ua ou iloa o oe o le fafine lalelei;", "I know that thou art a fair woman to look upon:"]]},
  {num:12,words:[["a vaai ia te oe tagata Aikupito,", "Therefore it shall come to pass, when the Egyptians shall see thee,"], ["ona latou faapea ane lea. O lana avā lena;", "that they shall say,"], ["ona latou fasioti lea ia te au,", "This is his wife:"], ["a e faaolaina oe.", "and they will kill me, but they will save thee alive."]]},
  {num:13,words:[["Se'i e fai atu o lo'u tuafafine oe,", "Say, I pray thee,"], ["ina ia ou saogalemu ai ona o oe;", "thou art my sister:"], ["e ola ai foi a'u ona o oe.", "that it may be well with me for thy sake; and my soul shall live because of thee."]]},
  {num:14,words:[["Ua oo foi Aperamo i Aikupito,", "And it came to pass, that,"], ["ona vaaia mai lea e tagata Aikupito o le fafine ua lalelei tasi lava ia.", "when Abram was come into Egypt, the Egyptians beheld the woman that she was very fair."]]},
  {num:15,words:[["Ua ilo atu foi o ia e alii sa ia Farao,", "The princes also of Pharaoh saw her,"], ["ma ua vivii ia te ia ia Farao;", "and commended her before Pharaoh:"], ["ona avane ai lea o le fafine i le fale o Farao.", "and the woman was taken into Pharaoh's house."]]},
  {num:16,words:[["Ona agalelei atu lea o ia ia Aperamo ona o ia;", "And he entreated Abram well for her sake:"], ["sa ia te ia foi o mamoe,", "and he had sheep,"], ["ma povi,", "and oxen,"], ["ma asini poa ma auauna tane,", "and he asses, and menservants,"], ["ma auauna fafine,", "and maidservants,"], ["ma asini fafine,", "and she asses,"], ["ma kamela.", "and camels."]]},
  {num:17,words:[["A ua faatigaina e Ieova o Farao ma lona aiga i mala tetele ona o Sarai le avā a Aperamo.", "And the LORD plagued Pharaoh and his house with great plagues because of Sarai Abram's wife."]]},
  {num:18,words:[["Ona valaau ai lea o Farao ia Aperamo,", "And Pharaoh called Abram,"], ["ua faapea atu,", "and said,"], ["Se a lenei mea ua e faia ia te au? Pe se a le mea na e le ta'u mai ai ia te au o lau avā ia?", "What is this that thou hast done unto me? why didst thou not tell me that she was thy wife?"]]},
  {num:19,words:[["O le a le mea na e faapea mai ai,", "Why saidst thou,"], ["O lo'u tuafafine ia? Na fai a'u mao avea o ia e fai ma'u avā; o lenei foi,", "She is my sister? so I might have taken her to me to wife:"], ["faauta,", "now therefore behold thy wife,"], ["o lau avā lea, ina ave ia,", "take her,"], ["ma lua o.", "and go thy way."]]},
  {num:20,words:[["Ona poloai atu lea o Farao i ona tagata ia te ia;", "And Pharaoh commanded his men concerning him:"], ["ona latou tuuina atu ai lea o ia la te o ma lana avā,", "and they sent him away, and his wife,"], ["atoa ma ana mea uma.", "and all that he had."]]},
];
renderVerseSet(gen_ch_12_Verses, 'gen-ch12-verses');

var gen_ch_13_Verses = [
  {num:1,words:[["Ua alu ae Aperamo nai Aikupito o ia,", "And Abram went up out of Egypt,"], ["ma lana avā,", "he,"], ["ma ana mea uma,", "and his wife, and all that he had,"], ["o Lota foi faatasi ma ia,", "and Lot with him,"], ["e o i le itu i toga.", "into the south."]]},
  {num:2,words:[["Ua mauoa tele lava Aperamo i manu,", "And Abram was very rich in cattle,"], ["ma ario,", "in silver,"], ["ma auro.", "and in gold."]]},
  {num:3,words:[["Ua alu foi o ia i lana malaga nai le itu i toga ua oo i Peteli,", "And he went on his journeys from the south even to Beth-el,"], ["i le mea lava sa muai i ai lona fale ie,", "unto the place where his tent had been at the beginning,"], ["i le va o Peteli ma Ai;", "between Beth-el and Hai;"]]},
  {num:4,words:[["o le mea na i ai le fata faitaulaga sa na muai faia i lea mea;", "Unto the place of the altar, which he had made there at the first:"], ["ua valaau atu ai foi Aperamo i le suafa o Ieova.", "and there Abram called on the name of the LORD."]]},
  {num:5,words:[["O Lota foi,", "And Lot also,"], ["sa la o ma Aperamo,", "which went with Abram,"], ["sa ia te ia o mamoe,", "had flocks,"], ["ma povi,", "and herds,"], ["ma fale ie.", "and tents."]]},
  {num:6,words:[["Ua le mafai lava ona la mau faatasi i le nuu,", "And the land was not able to bear them,"], ["auā sa tele lava a laua mea,", "that they might dwell together: for their substance was great,"], ["ua le mafai ai ona la mau faatasi.", "so that they could not dwell together."]]},
  {num:7,words:[["Ua femisai foi leoleo o manu a Aperamo ma leoleo o manu a Lota;", "And there was a strife between the herdmen of Abram's cattle and the herdmen of Lot's cattle:"], ["o ona po foi ia sa mau ai sa Kananā ma sa Perisē i le nuu.", "and the Canaanite and the Perizzite dwelled then in the land."]]},
  {num:8,words:[["Ona fai atu lea o Aperamo ia Lota,", "And Abram said unto Lot, Let there be no strife,"], ["Aua lava ne'i femisa'i i taua,", "I pray thee,"], ["po o a taua leoleo manu:", "between me and thee,"], ["auā o le uso i taua.", "and between my herdmen and thy herdmen; for we be brethren."]]},
  {num:9,words:[["E le o i ou luma ea le laueleele uma? Se'i e te'a ese ma a'u. Afai e te alu i le itu tauagavale,", "Is not the whole land before thee? separate thyself, I pray thee,"], ["ona ou alu ai lea i le itu taumatau;", "from me: if thou wilt take the left hand,"], ["a ē alu i le itu taumatau,", "then I will go to the right;"], ["ona ou alu ai lea i le itu tauagavale.", "or if thou depart to the right hand, then I will go to the left."]]},
  {num:10,words:[["Ua vaavaai Lota,", "And Lot lifted up his eyes,"], ["ona ilo atu ai lea e ia i le fanua laugatasi uma ua i ai Ioritana,", "and beheld all the plain of Jordan,"], ["ua lafulemu uma lava,", "that it was well watered every where,"], ["e oo i Soara,", "before the LORD destroyed Sodom and Gomorrah,"], ["e pei o le faatoaga a Ieova,", "even as the garden of the LORD,"], ["e pei o le laueleele o Aikupito,", "like the land of Egypt,"], ["a o lei faaumatia e Ieova o Sotoma ma Komoro.", "as thou comest unto Zoar."]]},
  {num:11,words:[["Ona filifilia lea e Lota mona o le fanua laugatasi uma ua i ai Ioritana;", "Then Lot chose him all the plain of Jordan;"], ["ua aga'i atu foi Lota i sasae;", "and Lot journeyed east:"], ["ona la te'a eseese ai lea o le tasi ma le tasi.", "and they separated themselves the one from the other."]]},
  {num:12,words:[["Ua mau Aperamo i le nuu o Kanana,", "Abram dwelled in the land of Canaan,"], ["a o Lota ua mau ia i aai o le fanua laugatasi, ma ua faatuina ai lona fale ie,", "and Lot dwelled in the cities of the plain,"], ["ua oo atu i Sotoma.", "and pitched his tent toward Sodom."]]},
  {num:13,words:[["A o tagata o Sotoma ua leaga i latou, ma ua matuā agasala lava i luma o Ieova.", "But the men of Sodom were wicked and sinners before the LORD exceedingly."]]},
  {num:14,words:[["Ua fetalai atu foi Ieova ia Aperamo,", "And the LORD said unto Abram,"], ["ina ua te'a eseese o Lota ma ia,", "after that Lot was separated from him,"], ["Se'i e vaavaai ia,", "Lift up now thine eyes,"], ["ma ilo atu i le mea e te i ai na, i le itu i matu,", "and look from the place where thou art northward,"], ["ma le itu i toga,", "and southward,"], ["ma sasae,", "and eastward,"], ["ma sisifo;", "and westward:"]]},
  {num:15,words:[["auā o le laueleele uma ua e ilo atu nei,", "For all the land which thou seest, to thee will I give it,"], ["ou te foaiina atu mo oe ma lau fanau e faavavau.", "and to thy seed for ever."]]},
  {num:16,words:[["Ou te faia foi lau fanau e pei o le efuefu o le eleele;", "And I will make thy seed as the dust of the earth:"], ["afai e mafaia e se tagata ona faitauina o le efuefu o le eleele,", "so that if a man can number the dust of the earth,"], ["ona mafai lea ona faitaulia o lau lava fanau.", "then shall thy seed also be numbered."]]},
  {num:17,words:[["Ina tulai ia,", "Arise,"], ["ina fealualuai i le nuu i lona umi ma lona lautele;", "walk through the land in the length of it and in the breadth of it;"], ["auā ou te foaiinaatua mo oe.", "for I will give it unto thee."]]},
  {num:18,words:[["Ona ave lea e Aperamo lona fale ie,", "Then Abram removed his tent,"], ["ua alu atu ua mau i aluna o Mamere,", "and came and dwelt in the plain of Mamre,"], ["o i Heperona lea,", "which is in Hebron,"], ["ua ia faia foi i lea mea le fata faitaulaga ia Ieova.", "and built there an altar unto the LORD."]]},
];
