var gen_ch_14_Verses = [
  {num:1,words:[["O ona po o Amarafilo le tupu o Senara,", "And it came to pass in the days of Amraphel king of Shinar,"], ["o Arioka le tupu o Alasara,", "Arioch king of Ellasar,"], ["o Kitalaoma le tupu o Elama,", "Chedorlaomer king of Elam,"], ["ma Titalu le tupu o nuu;", "and Tidal king of nations;"]]},
  {num:2,words:[["na latou sii atu ai le taua ia Pira le tupu o Sotoma,", "That these made war with Bera king of Sodom,"], ["ma Piresa le tupu o Komoro,", "and with Birsha king of Gomorrah,"], ["ma Senapo le tupu o Atama,", "Shinab king of Admah,"], ["ma Semepo le tupu o Sepoima,", "and Shemeber king of Zeboiim,"], ["atoa ma le tupu o Pala,", "and the king of Bela,"], ["o Soara lea.", "which is Zoar."]]},
  {num:3,words:[["Ua faapotopoto i latou nei uma i le vanu o Setima,", "All these were joined together in the vale of Siddim,"], ["o le sami oona lea.", "which is the salt sea."]]},
  {num:4,words:[["E sefulu ma le lua o tausaga sa nofo pologa ai i latou ia Kitalaoma,", "Twelve years they served Chedorlaomer,"], ["ua oo i le tausaga e sefulu ma le tolu ona latou fou ai lea.", "and in the thirteenth year they rebelled."]]},
  {num:5,words:[["O lea tausaga foi e sefulu ma le fa ua o mai ai Kitalaoma,", "And in the fourteenth year came Chedorlaomer,"], ["ma tupu sa 'au faatasi ma ia,", "and the kings that were with him,"], ["ma latou fafasi i tagata o sa Rafā i Aserota Karenaima,", "and smote the Rephaims in Ashteroth Karnaim,"], ["ma tagata Susema i Hamo,", "and the Zuzims in Ham,"], ["ma tagata Emema i Save Kiriataima,", "and the Emims in Shaveh Kiriathaim,"]]},
  {num:6,words:[["ma sa Horī i lo latou mauga o Seira,", "And the Horites in their mount Seir,"], ["e oo atu i Eleparana,", "unto El-paran,"], ["e latalata lea i le vao.", "which is by the wilderness."]]},
  {num:7,words:[["Ua latou toe foi mai,", "And they returned,"], ["ua oo i Enemisipata,", "and came to En-mishpat,"], ["o Katesa lea,", "which is Kadesh, and smote all the country of the Amalekites,"], ["ma latou fafasi i le nuu uma o sa Amalekā,", "and also the Amorites,"], ["atoa foi ma sa Amorī sa nonofo i Haseso Tamara.", "that dwelt in Hazezon-tamar."]]},
  {num:8,words:[["Ua o atu foi le tupu o Sotoma,", "And there went out the king of Sodom,"], ["ma le tupu o Komoro,", "and the king of Gomorrah,"], ["ma le tupu o Atama, ma le tupu o Sepoima,", "and the king of Admah,"], ["ma le tupu o Pala,", "and the king of Zeboiim,"], ["o Soara lea;", "and the king of Bela (the same is Zoar;"], ["ma latou tau ai le taua ma i latou i le vanu o Setima;", ") and they joined battle with them in the vale of Siddim;"]]},
  {num:9,words:[["o i latou ,", "With Chedorlaomer the king of Elam,"], ["o Kitalaoma le tupu o Elama,", "and with Tidal king of nations,"], ["ma Titalu le tupu o nuu, ma Amarafilo le tupu o Senara,", "and Amraphel king of Shinar,"], ["ma Arioka le tupu o Alasara;", "and Arioch king of Ellasar;"], ["o tupu na e toafa ma ia tupu e toalima.", "four kings with five."]]},
  {num:10,words:[["Sa i ai foi i le vanu o Setima o lua o pulu emeri e tele lava;", "And the vale of Siddim was full of slimepits;"], ["na sosola foi le tupu o Sotoma ma le tupu o Komoro ma pauu i lea mea;", "and the kings of Sodom and Gomorrah fled, and fell there;"], ["a o e na totoe ua sosola i latou i le mauga.", "and they that remained fled to the mountain."]]},
  {num:11,words:[["Ona latou vetea lea o oloa uma o Sotoma ma Komoro,", "And they took all the goods of Sodom and Gomorrah,"], ["atoa ma a latou mea e 'ai uma,", "and all their victuals,"], ["ona o ai lea o i latou.", "and went their way."]]},
  {num:12,words:[["Ua latou avea foi Lota le atalii o le uso o Aperamo,", "And they took Lot,"], ["atoa ma ana oloa,", "Abram's brother's son,"], ["o ia foi sa nofo i Sotoma,", "who dwelt in Sodom, and his goods,"], ["ona o ai lea o i latou.", "and departed."]]},
  {num:13,words:[["Ua alu atu foi le tasi na sao ma ta'uatua ia Aperamo le Eperu,", "And there came one that had escaped,"], ["o lē sa mau i aluna o Mamere o sa Amorī,", "and told Abram the Hebrew;"], ["o le uso o Esekolo,", "for he dwelt in the plain of Mamre the Amorite, brother of Eshcol,"], ["o le uso foi o Aneri;", "and brother of Aner:"], ["o i latou na osi feagaiga ma Aperamo.", "and these were confederate with Abram."]]},
  {num:14,words:[["Ua faalogo Aperamo ua avea lona uso i le taua,", "And when Abram heard that his brother was taken captive,"], ["ona saunia lea e ia ona tagata ua a'oa'oina,", "he armed his trained servants,"], ["e na fananau i lona aiga,", "born in his own house,"], ["e toatolu selau ma le toasefulu ma le toavalu,", "three hundred and eighteen,"], ["ma ua tuliloa ia te i latou e oo i Tanu.", "and pursued them unto Dan."]]},
  {num:15,words:[["Ua ia tofia foi o 'au a ona tagata i le po e tau ma i latou,", "And he divided himself against them, he and his servants,"], ["ua fafasi foi ia te i latou,", "by night,"], ["ma tuli muliau ia te i latou ua oo i Hopa,", "and smote them,"], ["e i le itu tauagavale lea o Tamaseko.", "and pursued them unto Hobah, which is on the left hand of Damascus."]]},
  {num:16,words:[["Ua toe maua mai foi e ia o le oloa uma lava;", "And he brought back all the goods,"], ["ua ia toe maua mai foi Lota lona uso,", "and also brought again his brother Lot,"], ["ma aua oloa,", "and his goods,"], ["o fafine foi,", "and the women also,"], ["atoa ma le nuu.", "and the people."]]},
  {num:17,words:[["Ua alu atu foi le tupu o Sotoma e faafetaiai ia te ia i le vanu o Savee,", "And the king of Sodom went out to meet him after his return from the slaughter of Chedorlaomer,"], ["e ta'ua foi lea o le vanu o le tupu,", "and of the kings that were with him,"], ["ina ua toe foi mai i le taua ma Kitalaoma,", "at the valley of Shaveh,"], ["ma tupu sa 'au faatasi ma ia.", "which is the king's dale."]]},
  {num:18,words:[["A o Mekisateko le tupu o Salema ua avane e ia areto ma uaina;", "And Melchizedek king of Salem brought forth bread and wine:"], ["o le faitaulaga foi o ia a le Atua silisili ese.", "and he was the priest of the most high God."]]},
  {num:19,words:[["Ua ia faamanuia foi ia te ia,", "And he blessed him,"], ["ua faapea atu,", "and said,"], ["Ia manuia Aperamo i le Atua silisili ese,", "Blessed be Abram of the most high God,"], ["e ona le lagi ma le lalologi;", "possessor of heaven and earth:"]]},
  {num:20,words:[["ia faafetaia foi le Atua silisili ese,", "And blessed be the most high God,"], ["o le na tuuina mai ou fili i ou lima. Ua foai atu foi e Aperamo ia te ia o mea e sefulu a'i o mea uma.", "which hath delivered thine enemies into thy hand. And he gave him tithes of all."]]},
  {num:21,words:[["Ua fai mai foi le tupu o Sotoma ia Aperamo,", "And the king of Sodom said unto Abram,"], ["Tuu mai ia ia te au o tagata,", "Give me the persons,"], ["a e ave ma oe le oloa.", "and take the goods to thyself."]]},
  {num:22,words:[["A ua tali atu Aperamo i le tupu o Sotoma,", "And Abram said to the king of Sodom,"], ["Ua sii lo'u lima ia Ieova,", "I have lift up mine hand unto the LORD,"], ["le Atua silisili ese,", "the most high God,"], ["e ona le lagi ma le lalolagi,", "the possessor of heaven and earth,"]]},
  {num:23,words:[["ou te le avea lava sina manoa po o sina nonoa seevae,", "That I will not take from a thread even to a shoelatchet,"], ["ou te le avea lava sina mea i au mea uma,", "and that I will not take any thing that is thine,"], ["ina ne'i faapea a oe,", "lest thou shouldest say,"], ["Ua mauoa Aperamo ia te au.", "I have made Abram rich:"]]},
  {num:24,words:[["Tau lava o mea ua uma ona aai e taulelea,", "Save only that which the young men have eaten,"], ["ma vaegāoloa a tagata na matou o ma a'u,", "and the portion of the men which went with me,"], ["o Aneri,", "Aner,"], ["ma Esekolo,", "Eshcol,"], ["ma Mamere,", "and Mamre;"], ["ia latou ave a latou vaegāoloa.", "let them take their portion."]]},
];
