var gen_ch_16_Verses = [
  {num:1,words:[["A o Sarai le avā a Aperamo,", "Now Sarai Abram's wife bare him no children:"], ["ua le fanau ia ia te ia;", "and she had an handmaid,"], ["sa ia te ia foi le auauna fafine, o le Aikupito,", "an Egyptian,"], ["o Akara lona igoa.", "whose name was Hagar."]]},
  {num:2,words:[["Na fai atu foi Sarai ia Aperamo,", "And Sarai said unto Abram,"], ["Faauta mai ea,", "Behold now,"], ["ua finagalo Ieova ia ou le fanau;", "the LORD hath restrained me from bearing: I pray thee,"], ["se'i e alu ane i la'u auauna fafine;", "go in unto my maid;"], ["atonu ou te maua ai ni tama ia te ia.", "it may be that I may obtain children by her."], ["Ua usiusitai foi Aperamo i le upu a Sarai.", "And Abram hearkened to the voice of Sarai."]]},
  {num:3,words:[["O Sarai foi le avā a Aperamo, na ia ave ia Akara,", "And Sarai Abram's wife took Hagar her maid the Egyptian,"], ["o le Aikupito, o lana auauna fafine, ma tuuina atu ia Aperamo lana tane,", "after Abram had dwelt ten years in the land of Canaan,"], ["e fai mana avā, ina ua mavae o tausaga e sefulu sa nofo ai Aperamo i le nuu o Kanana.", "and gave her to her husband Abram to be his wife."]]},
  {num:4,words:[["Ona alu ane lea o ia ia Akara,", "And he went in unto Hagar,"], ["ona to ai lea o ia;", "and she conceived:"], ["ua iloa e ia ua to o ia,", "and when she saw that she had conceived,"], ["ona faaleaogaina lea e ia o lona matai fafine.", "her mistress was despised in her eyes."]]},
  {num:5,words:[["Ona fai atu lea o Sarai ia Aperamo,", "And Sarai said unto Abram,"], ["Ia i luga ia te oe lo'u agaleagaina;", "My wrong be upon thee:"], ["o a'u nei foi, na ou tuuina atu la'u auauna fafine ia te oe;", "I have given my maid into thy bosom;"], ["ua iloa foi e ia ua to o ia,", "and when she saw that she had conceived,"], ["ona faaleaogaina ai lea o a'u e ia;", "I was despised in her eyes:"], ["ia faamasino mai Ieova ia te i taua.", "the LORD judge between me and thee."]]},
  {num:6,words:[["Ona tali mai lea o Aperamo ia Sarai,", "But Abram said unto Sarai,"], ["Faauta,", "Behold,"], ["o ia te oe le pule i lau auauna fafine,", "thy maid is in thy hand;"], ["faitalia lava oe se mea e te faia ia te ia. Ua agaleaga foi Sarai ia te ia,", "do to her as it pleaseth thee. And when Sarai dealt hardly with her,"], ["ona sola ese ai lea o ia i ona luma.", "she fled from her face."]]},
  {num:7,words:[["Ua maua foi o ia e le agelu a Ieova i le vaipuna i le vao,", "And the angel of the LORD found her by a fountain of water in the wilderness,"], ["o le vaipuna i le ala i Sara.", "by the fountain in the way to Shur."]]},
  {num:8,words:[["Ona faapea atu lea o ia,", "And he said,"], ["Akara e,", "Hagar,"], ["le anauna a Sarai,", "Sarai's maid,"], ["maifea oe? O fea ea a e alu i ai? Ona tali mai lea o ia,", "whence camest thou? and whither wilt thou go? And she said,"], ["Ua ou sola mai ia Sarai o lo'u matai.", "I flee from the face of my mistress Sarai."]]},
  {num:9,words:[["Ona faapea atu lea o le agelu a Ieova ia te ia,", "And the angel of the LORD said unto her, Return to thy mistress,"], ["Ia e foi atu i lou matai ma e faamaulalo atu ia te ia.", "and submit thyself under her hands."]]},
  {num:10,words:[["Ua fetalai atu foi le agelu a Ieova ia te ia,", "And the angel of the LORD said unto her,"], ["Ou te matuā faatoateleina lava lau fanau,", "I will multiply thy seed exceedingly,"], ["e le mafai lava ona faitau ina ua toatele.", "that it shall not be numbered for multitude."]]},
  {num:11,words:[["Ua fetalai atu foi le agelu a Ieova ia te ia,", "And the angel of the LORD said unto her,"], ["Faauta,", "Behold,"], ["ua e to,", "thou art with child,"], ["o le a e fanau mai se tama tane,", "and shalt bear a son,"], ["e te faaigoa foi ia te ia o Isamaeli;", "and shalt call his name Ishmael;"], ["auā ua faafofogaina e Ieova lou tiga.", "because the LORD hath heard thy affliction."]]},
  {num:12,words:[["E fai o ia ma tagata e tusa ma le asini o le vao;", "And he will be a wild man;"], ["e fai tagata uma mona fili,", "his hand will be against every man,"], ["e fai foi o ia ma fili o tagata uma;", "and every man's hand against him;"], ["e mau foi o ia i luma o ona uso uma.", "and he shall dwell in the presence of all his brethren."]]},
  {num:13,words:[["Ona faaigoaina lea e ia le suafa o Ieova o le na fetalai mai ia te ia,", "And she called the name of the LORD that spake unto her,"], ["O oe le Atua le ua faaali mai ia te au;", "Thou God seest me:"], ["auā ua faapea ana,", "for she said,"], ["Ua ou vaai atu ea iinei i tua o loo silasila mai ia te au?", "Have I also here looked after him that seeth me?"]]},
  {num:14,words:[["O le mea lea ua faaigoaina ai le vaieli,", "Wherefore the well was called Beer-lahai-roi;"], ["o Pere-laaroi, faauta,", "behold,"], ["o loo i le va o Katesa ma Pareta.", "it is between Kadesh and Bered."]]},
  {num:15,words:[["Ua fanau mai foi Akara le atalii ia Aperamo;", "And Hagar bare Abram a son:"], ["ua faaigoaina foi e Aperamo lona atalii na fanau mai ia Akara,", "and Abram called his son's name, which Hagar bare,"], ["o Isamaeli.", "Ishmael."]]},
  {num:16,words:[["O le valu sefulu ma le ono o tausaga o Aperamo na fanau mai ai Akara o Isamaeli le atalii o Aperamo.", "And Abram was fourscore and six years old, when Hagar bare Ishmael to Abram."]]},
];
