var gen_ch_44_Verses = [
  {num:1,words:[["Ua ia fai atu foi i le na pule i lona aiga,", "And he commanded the steward of his house,"], ["ua faapea atu,", "saying,"], ["Ia faatutumu taga a ia tagata i mea e 'ai,", "Fill the men's sacks with food,"], ["ia tuugataina i latou;", "as much as they can carry,"], ["ia tuu foi tupe a le tagata taitasi i le gutu o lana taga.", "and put every man's money in his sack's mouth."]]},
  {num:2,words:[["I tuu foi la'u ipu faaofuofu,", "And put my cup,"], ["le ipu ario,", "the silver cup,"], ["i le gutu o le taga a le aupito itiiti,", "in the sack's mouth of the youngest,"], ["atoa ma tupe o lana saito. Ona faia lea e ia faapei ona fai atu ai e Iosefa.", "and his corn money. And he did according to the word that Joseph had spoken."]]},
  {num:3,words:[["Ua malama ae le taeao,", "As soon as the morning was light,"], ["ona aauina atu lea o ia tagata,", "the men were sent away,"], ["o i latou atoa ma a latou asini.", "they and their asses."]]},
  {num:4,words:[["Ua tuanai e i latou le aai,", "And when they were gone out of the city,"], ["a e lei mamao foi,", "and not yet far off,"], ["ona fai atu ai lea o Iosefa i le ua pule i lona aiga,", "Joseph said unto his steward,"], ["Tu ia i luga,", "Up,"], ["tuliloa atu ia i na tagata;", "follow after the men;"], ["pe a e maua atu foi ia te i latou,", "and when thou dost overtake them,"], ["ia e fai atu i ai,", "say unto them,"], ["Se a le mea ua outou taui mai ai le lelei i le leaga?", "Wherefore have ye rewarded evil for good?"]]},
  {num:5,words:[["E le o le mea ea lena e inu ai lo'u alii,", "Is not this it in which my lord drinketh,"], ["ma ua iite ai lava? Ua outou agaleaga mai i le mea ua outou faia.", "and whereby indeed he divineth? ye have done evil in so doing."]]},
  {num:6,words:[["Na ia maua atu foi ia te i latou,", "And he overtook them,"], ["ona fai atu ai lea ia te i latou ia lava upu.", "and he spake unto them these same words."]]},
  {num:7,words:[["Ona latou fai mai ai lea ia te ia. Se a ea le mea e faapea mai ai ia upu e le alii? E mamao ma au auauna ona latou fai se mea faapena.", "And they said unto him, Wherefore saith my lord these words? God forbid that thy servants should do according to this thing:"]]},
  {num:8,words:[["Faauta ea,", "Behold, the money,"], ["o tupe na matou maua i gutu o a matou taga na matou toe au mai ia te oe ai le nuu o Kanana;", "which we found in our sacks' mouths,"], ["se a le mea a matou gaoi ai ario po o auro i le maota o lou alii?", "we brought again unto thee out of the land of Canaan: how then should we steal out of thy lord's house silver or gold?"]]},
  {num:9,words:[["O so matou o au auauna e maua ai le mea,", "With whomsoever of thy servants it be found,"], ["ia oti lava ia;", "both let him die,"], ["e fai foi i matou ma pologa ia te oe lo matou alii.", "and we also will be my lord's bondmen."]]},
  {num:10,words:[["Ona fai atu ai lea o ia,", "And he said,"], ["O lena lava,", "Now also let it be according unto your words:"], ["ia faia a outou upu; o le ua i ai le mea ia fai lea mo'u pologa,", "he with whom it is found shall be my servant;"], ["a e magalo outou.", "and ye shall be blameless."]]},
  {num:11,words:[["Ona latou taitasi ai lea ma vave tuu i lalo lana taga i le eleele,", "Then they speedily took down every man his sack to the ground,"], ["ua taitasi foi ma tatala lana taga.", "and opened every man his sack."]]},
  {num:12,words:[["Ona ia suesue ai lea,", "And he searched,"], ["ua amata i le aupito matua,", "and began at the eldest,"], ["ua oo i le aupito itiiti,", "and left at the youngest:"], ["ua maua foi le ipu i le taga a Peniamina.", "and the cup was found in Benjamin's sack."]]},
  {num:13,words:[["Ona latou saei ai lea o latou ofu,", "Then they rent their clothes,"], ["ua taitasi ma faaee le avega i lana asini,", "and laded every man his ass,"], ["ma latou foi atu i le aai.", "and returned to the city."]]},
  {num:14,words:[["Ua o ma Iuta ma ona uso i le fale o Iosefa,", "And Judah and his brethren came to Joseph's house;"], ["auā na i ai pea ia;", "for he was yet there:"], ["ona latou faapauu fao mai ai lea i ona luma.", "and they fell before him on the ground."]]},
  {num:15,words:[["Ona fai atu ai lea o Iosefa ia te i latou,", "And Joseph said unto them,"], ["Se a lenei mea ua outou faia? po ua outou le iloa ea e mafai lava e le tagata faapei o a'u nei ona iite?", "What deed is this that ye have done? wot ye not that such a man as I can certainly divine?"]]},
  {num:16,words:[["Ona tali mai lea o Iuta,", "And Judah said,"], ["Se a se mea matou te fai atu i lo matou alii? Se a sa matou upu? Pe faapefea ona matou faatonuina atu o i matou? Ua faaalia e le Atua le agasala a au auauna;", "What shall we say unto my lord? what shall we speak? or how shall we clear ourselves? God hath found out the iniquity of thy servants:"], ["faauta,", "behold, we are my lord's servants,"], ["o auauna i matou ia te oe lo matou alii,", "both we,"], ["o i matou atoa ma le ua maua ua iai le ipu.", "and he also with whom the cup is found."]]},
  {num:17,words:[["Ona fai atu ai lea o ia,", "And he said,"], ["E mamao ia te au ona ou fai lea mea;", "God forbid that I should do so:"], ["o le ua maua ua i ai le ipu,", "but the man in whose hand the cup is found,"], ["e fai lea ma'u auauna,", "he shall be my servant;"], ["a o outou,", "and as for you,"], ["o pea ia outou ma le manuia i lo outou tamā.", "get you up in peace unto your father."]]},
  {num:18,words:[["Ona soso mai ai lea o Iuta ia te ia,", "Then Judah came near unto him,"], ["ua faapea mai,", "and said, Oh my lord,"], ["Le alii e,", "let thy servant,"], ["tuu mai ia i lau auauna se'i fai atu se upu e faafofoga i ai oe le alii,", "I pray thee,"], ["aua foi ne'i e toatamai ai i lau auauna;", "speak a word in my lord's ears, and let not thine anger burn against thy servant:"], ["auā o oe e faapei o Farao lava.", "for thou art even as Pharaoh."]]},
  {num:19,words:[["Le alii e,", "My lord asked his servants,"], ["na e fesili mai i au auauna,", "saying,"], ["ua faapea mai, Pe ai so outou tamā,", "Have ye a father,"], ["po o so outou uso?", "or a brother?"]]},
  {num:20,words:[["Ona matou fai atu ai lea ia te oe lo matou alii,", "And we said unto my lord,"], ["O lo matou tamā lava,", "We have a father,"], ["o le toeaina,", "an old man,"], ["ma le tama na fanaua e ia ina ua toeaina,", "and a child of his old age,"], ["o le tama itiiti;", "a little one;"], ["ua oti foi lona uso,", "and his brother is dead,"], ["o le toe tama foi ia a lona tinā,", "and he alone is left of his mother,"], ["e faapelepele lava lona tamā ia te ia.", "and his father loveth him."]]},
  {num:21,words:[["Ona e fetalai mai lea i au auauna,", "And thou saidst unto thy servants,"], ["Ia au mai o ia ia te au,", "Bring him down unto me,"], ["ou te matamata i ai.", "that I may set mine eyes upon him."]]},
  {num:22,words:[["Ona matou fai atu ai lea i lo matou alii,", "And we said unto my lord,"], ["E le mafai ona tuua e le tama lona tamā;", "The lad cannot leave his father: for if he should leave his father,"], ["auā pe afai na te tuua lona tamā e oti lava lona tamā .", "his father would die."]]},
  {num:23,words:[["Ona e fetalai mai ai lea i au auauna,", "And thou saidst unto thy servants,"], ["Afai tou te le o mai ma lo outou uso aupito itiiti,", "Except your youngest brother come down with you,"], ["tatou te le toe fesilafai.", "ye shall see my face no more."]]},
  {num:24,words:[["Ua o ae i matou i lau auauna o lo matou tama,", "And it came to pass when we came up unto thy servant my father,"], ["ona matou ta'u atu ai lea ia te ia le fetalaiga a lo matou alii.", "we told him the words of my lord."]]},
  {num:25,words:[["Ua fai mai foi lo matou tamā,", "And our father said, Go again,"], ["Toe ō ia e faatau mai sina mea e 'ai mā tatou.", "and buy us a little food."]]},
  {num:26,words:[["Ona matou fai atu ai lea,", "And we said,"], ["E le mafai ona matou o ifo;", "We cannot go down:"], ["a e afai matou te o ma lo matou uso aupito itiiti,", "if our youngest brother be with us, then will we go down:"], ["ona matou o ifo ai lea;", "for we may not see the man's face,"], ["auā e le mafai ona matou iloa o fofoga o le alii pe afai e le i ai ia te i matou lo matou uso aupito itiiti.", "except our youngest brother be with us."]]},
  {num:27,words:[["Ona fai mai ai lea o lau auauna, o lo matou tamā,", "And thy servant my father said unto us,"], ["ia te i matou, Ua outou iloa na fanau mai la'u avā ia te au o atalii e toalua.", "Ye know that my wife bare me two sons:"]]},
  {num:28,words:[["Na alu ese foi le tasi ia te au,", "And the one went out from me,"], ["ona ou faapea ane ai lea,", "and I said,"], ["Ai lava ua saeia lava ia,", "Surely he is torn in pieces;"], ["ou te lei toe iloa foi ia talu ai.", "and I saw him not since:"]]},
  {num:29,words:[["Afai tou te aveeseina foi lenei ia te au,", "And if ye take this also from me,"], ["a oo atu foi ia te ia se leaga,", "and mischief befall him,"], ["tou te aveina ifo ai o'u lauulu sina i le tuugamau ma le faanoanoa.", "ye shall bring down my gray hairs with sorrow to the grave."]]},
  {num:30,words:[["O lenei, pe a a'u alu atu i lau auauna o lo'u tamā,", "Now therefore when I come to thy servant my father,"], ["a e le o ia te i matou le tama,", "and the lad be not with us;"], ["(auā o le ola o le tama e ola ai o ia, )", "seeing that his life is bound up in the lad's life;"]]},
  {num:31,words:[["pe a iloa e ia e le o i ai le tama,", "It shall come to pass,"], ["ona oti ai lea;", "when he seeth that the lad is not with us,"], ["ona aveina ifo ai lea e au anauna o lauulu sinā o lau auauna, o lo matou tamā,", "that he will die:"], ["i le tuugamau ma le faanoanoa.", "and thy servants shall bring down the gray hairs of thy servant our father with sorrow to the grave."]]},
  {num:32,words:[["Auā na fai lau auauna ma moni o le tama i lo'u tamā,", "For thy servant became surety for the lad unto my father,"], ["ua faapea atu,", "saying,"], ["Afai ou te le toe aumaia o ia ia te oe,", "If I bring him not unto thee,"], ["ona ou nofo sala ai lea i lo'u tamā i aso uma.", "then I shall bear the blame to my father for ever."]]},
  {num:33,words:[["O lenei,", "Now therefore,"], ["ou te aioi atu;", "I pray thee,"], ["ia nofo a'u o lau auauna e fai ma pologa i lo'u alii e sui a'i le tama,", "let thy servant abide instead of the lad a bondman to my lord;"], ["a ia alu ae le tama faatasi ma ona uso;", "and let the lad go up with his brethren."]]},
  {num:34,words:[["auā ou te mafaia faapefea ona alu ae i lo'u tamā,", "For how shall I go up to my father,"], ["a e le o ia te au le tama? Ne'i ou iloa le leaga e oo i lo'u tamā.", "and the lad be not with me? lest peradventure I see the evil that shall come on my father."]]},
];
renderVerseSet(gen_ch_44_Verses, 'gen-ch44-verses');

var gen_ch_45_Verses = [
  {num:1,words:[["Ona le mafai ai lea e Iosefa ona oono i luma o latou uma na tutū mai i ona luma,", "Then Joseph could not refrain himself before all them that stood by him;"], ["ona alaga ai lea o ia,", "and he cried,"], ["Ia o ese tagata uma ia te au.", "Cause every man to go out from me."], ["E lei tu mai foi se tasi ia Iosefa ina ua faaali o ia i ona uso.", "And there stood no man with him, while Joseph made himself known unto his brethren."]]},
  {num:2,words:[["Ua na tagi foi ma le leo tele; ona lagona ai lea e tagata Aikupito,", "And he wept aloud:"], ["ua lagona foi e le aiga o Farao.", "and the Egyptians and the house of Pharaoh heard."]]},
  {num:3,words:[["Ua fai atu Iosefa i ona uso,", "And Joseph said unto his brethren,"], ["O a'u o Iosefa;", "I am Joseph;"], ["o ola mai pea ea lo'u tamā? Ona le mafai ai lea e ona uso ona tali mai ia te ia;", "doth my father yet live? And his brethren could not answer him;"], ["auā ua matuā atuatuvale i ona luma.", "for they were troubled at his presence."]]},
  {num:4,words:[["Ona fai atu ai lea o Iosefa i ona uso,", "And Joseph said unto his brethren, Come near to me,"], ["Ina soso mai ia ia te au.", "I pray you."], ["Ona latou soso mai ai lea.", "And they came near."], ["Ona fai atu ai lea o ia,", "And he said,"], ["O a'u o lo outou uso o Iosefa,", "I am Joseph your brother,"], ["na outou faatau mai i Aikupito.", "whom ye sold into Egypt."]]},
  {num:5,words:[["O lenei,", "Now therefore be not grieved,"], ["aua ne'i tiga outou,", "nor angry with yourselves,"], ["pe fai ma mea leaga i o outou manatu ina ua outou faatau mai ia te au i le mea nei;", "that ye sold me hither:"], ["auā na auina mai a'u e le Atua e muamua ia te outou e fai ma faaola;", "for God did send me before you to preserve life."]]},
  {num:6,words:[["auā o ia tausaga e lua ua i ai le oge i le nuu,", "For these two years hath the famine been in the land: and yet there are five years,"], ["o loo totoe foi tausaga e lima e le i ai se galuega i le suasolo po o se seleselegāsaito", "in the which there shall neither be earing nor harvest."]]},
  {num:7,words:[["Na auna mai foi a'u e le Atua e muamua ia te outou e faasaoina outou i le lalolagi,", "And God sent me before you to preserve you a posterity in the earth,"], ["e faaola foi ia te outou i le faaolataga tele.", "and to save your lives by a great deliverance."]]},
  {num:8,words:[["O lenei,", "So now it was not you that sent me hither,"], ["e le o outou na auna mai a'u iinei,", "but God:"], ["a o le Atua; ua ia fai foi a'u ma tamā o Farao,", "and he hath made me a father to Pharaoh,"], ["ma alii i lona aiga uma,", "and lord of all his house,"], ["ma pule i le nuu uma o Aikupito.", "and a ruler throughout all the land of Egypt."]]},
  {num:9,words:[["Ia outou vave ona o ae i lo'u tamā,", "Haste ye,"], ["ma outou fai atu ia te ia,", "and go up to my father,"], ["O faapea mai lou atalii o Iosefa,", "and say unto him, Thus saith thy son Joseph,"], ["Ua fai a'u e le Atua ma alii o Aikupito uma;", "God hath made me lord of all Egypt:"], ["ia e sau ia te au,", "come down unto me,"], ["aua e te tuai mai.", "tarry not:"]]},
  {num:10,words:[["E te nofo foi i le nuu o Kosena,", "And thou shalt dwell in the land of Goshen,"], ["e te latalata mai ia te au,", "and thou shalt be near unto me,"], ["o oe,", "thou,"], ["ma au fanau,", "and thy children,"], ["ma fanau a au fanau,", "and thy children's children,"], ["ma au mamoe,", "and thy flocks,"], ["ma au povi,", "and thy herds,"], ["ma au mea uma;", "and all that thou hast:"]]},
  {num:11,words:[["ou te tausi foi ia te oe i lea mea,", "And there will I nourish thee;"], ["auā e toe lima tausaga o le oge,", "for yet there are five years of famine;"], ["ina ne'i faamativaina ai oe,", "lest thou, and thy household,"], ["ma lou aiga,", "and all that thou hast,"], ["ma mea uma ua ia te oe.", "come to poverty."]]},
  {num:12,words:[["Faauta,", "And,"], ["ua iloa mai o outou mata,", "behold,"], ["ma mata o lo'u uso o Peniamina,", "your eyes see, and the eyes of my brother Benjamin,"], ["o lo'u lava gutu o lē tautala atu nei ia te outou.", "that it is my mouth that speaketh unto you."]]},
  {num:13,words:[["Ia outou ta'u atu foi i lo'u tamā lo'u mamalu uma i Aikupito,", "And ye shall tell my father of all my glory in Egypt,"], ["ma mea uma ua outou vaai i ai;", "and of all that ye have seen;"], ["ia outou faataalise foi ona au mai o lo'u tamā iinei.", "and ye shall haste and bring down my father hither."]]},
  {num:14,words:[["Ona fusi ai lea o ia ia Peniamina lona uso,", "And he fell upon his brother Benjamin's neck,"], ["ma tagi i lona ua;", "and wept;"], ["ua tagi foi Peniamina i lona ua.", "and Benjamin wept upon his neck."]]},
  {num:15,words:[["Ua taufeasogi foi ma ona uso uma,", "Moreover he kissed all his brethren, and wept upon them:"], ["ma tagi ia te i latou. Mulimuli ane ona fetautalatalai lea ona uso ma ia.", "and after that his brethren talked with him."]]},
  {num:16,words:[["Ua logoa foi le tala i le maota o Farao,", "And the fame thereof was heard in Pharaoh's house,"], ["ua faapea,", "saying,"], ["Ua o mai uso o Iosefa;", "Joseph's brethren are come: and it pleased Pharaoh well,"], ["ua fiafia ai Farao ma ana auauna.", "and his servants."]]},
  {num:17,words:[["Ona fetalai mai lea o Farao ia Iosefa,", "And Pharaoh said unto Joseph,"], ["Ia e fai atu i ou uso,", "Say unto thy brethren,"], ["Ia outou faia le mea nei;", "This do ye; lade your beasts,"], ["faaee mea i a outou manu,", "and go,"], ["ma ia outou o i le nuu o Kanana,", "get you unto the land of Canaan;"]]},
  {num:18,words:[["ia outou au mai ai lo outou tamā ma o outou aiga,", "And take your father and your households,"], ["ma ia outou o mai ia te au;", "and come unto me:"], ["ou te avatu ia te outou le lelei o le nuu o Aikupito;", "and I will give you the good of the land of Egypt,"], ["tou te aai ai mea e sili ona lelei o i le nuu.", "and ye shall eat the fat of the land."]]},
  {num:19,words:[["A o oe,", "Now thou art commanded,"], ["ua oo ia te oe le poloaiga,", "this do ye;"], ["ia outou fai le mea nei, ia ave fata faataavalevale ai le nuu o Aikupito mo a outou fanau,", "take you wagons out of the land of Egypt for your little ones,"], ["ma a outou avā,", "and for your wives,"], ["ma outou au mai lo outou tamā,", "and bring your father,"], ["i le o mai ai.", "and come."]]},
  {num:20,words:[["Aua foi ne'i manatua a outou mea;", "Also regard not your stuff;"], ["auā e ia te outou le lelei o le nuu uma o Aikupito.", "for the good of all the land of Egypt is your's."]]},
  {num:21,words:[["Ua faapea ona faia e atalii o Isaraelu;", "And the children of Israel did so:"], ["ua avatu foi e Iosefa o fata faataavalevale ia te i latou,", "and Joseph gave them wagons,"], ["faapei o le fetalaiga o Farao;", "according to the commandment of Pharaoh,"], ["na ia avatu foi ia te i latou o oso o le malaga.", "and gave them provision for the way."]]},
  {num:22,words:[["Na ia avatu foi ia te i latou uma e taitasi ma lona ofu;", "To all of them he gave each man changes of raiment;"], ["a o Peniamina,", "but to Benjamin he gave three hundred pieces of silver,"], ["na ia avatu i ai tupe e tolu galau ma ofu e lima.", "and five changes of raiment."]]},
  {num:23,words:[["A o lona tamā, ua ia aveina atu i ai nei mea;", "And to his father he sent after this manner;"], ["o asini e sefulu ua ave ai mea lelei a Aikupito, ma asini fafine e sefulu ua ave ai saito,", "ten asses laden with the good things of Egypt,"], ["ma areto, atoa ma mea e 'ai mā lona tamā i le malaga.", "and ten she asses laden with corn and bread and meat for his father by the way."]]},
  {num:24,words:[["Ona ia aauina atu lea o ona uso,", "So he sent his brethren away,"], ["ona latou o ai lea;", "and they departed:"], ["ua na fai atu foi ia te i latou,", "and he said unto them,"], ["Aua ne'i outou femisai i le ala.", "See that ye fall not out by the way."]]},
  {num:25,words:[["Ua latou o ae ai Aikupito,", "And they went up out of Egypt,"], ["ua o mai i le nuu o Kanana ia Iakopo lo latou tamā.", "and came into the land of Canaan unto Jacob their father,"]]},
  {num:26,words:[["Ona latou ta'u atu lea ia te ia,", "And told him,"], ["ua faapea atu,", "saying,"], ["O loo ola Iosefa,", "Joseph is yet alive,"], ["ua pule foi o ia i le nuu uma o Aikupito. Ona vaivai ai lea o lona loto,", "and he is governor over all the land of Egypt. And Jacob's heart fainted,"], ["auā ua na le talia a latou upu.", "for he believed them not."]]},
  {num:27,words:[["A ua latou tautala atu ia te ia i upu uma a Iosefa na ia tautala mai ai ia te i latou;", "And they told him all the words of Joseph,"], ["ua ia iloa foi fata faataavalevale na aauina mai e Iosefa e aami ia te ia,", "which he had said unto them: and when he saw the wagons which Joseph had sent to carry him,"], ["ona toe malosi ai lea o le loto o Iakopo lo latou tamā.", "the spirit of Jacob their father revived:"]]},
  {num:28,words:[["Ona faapea mai ai lea o Isaraelu,", "And Israel said,"], ["Soia,", "It is enough;"], ["o loo ola mai pea lo'u atalii o Iosefa; ou te alu,", "Joseph my son is yet alive:"], ["ma te feiloai ma ia manū ou te lei oti.", "I will go and see him before I die."]]},
];
renderVerseSet(gen_ch_45_Verses, 'gen-ch45-verses');

var gen_ch_46_Verses = [
  {num:1,words:[["Ona alu atu lea o Isaraelu ma ana mea uma,", "And Israel took his journey with all that he had,"], ["ua oo atu foi i Peresepa;", "and came to Beer-sheba,"], ["ua fai ai foi o taulaga i le Atua o lona tamā o Isaako.", "and offered sacrifices unto the God of his father Isaac."]]},
  {num:2,words:[["Ona fetalai mai lea o le Atua ia Isaraelu i le faaaliga i le po,", "And God spake unto Israel in the visions of the night,"], ["ua faapea mai,", "and said,"], ["Iakopo,", "Jacob,"], ["Iakopo e! Ona tali mai ai lea o ia,", "Jacob. And he said,"], ["O a'u lenei.", "Here am I."]]},
  {num:3,words:[["Ona fetalai mai lea o ia,", "And he said,"], ["O a'u nei o le Atua,", "I am God,"], ["o le Atua o lou tamā;", "the God of thy father:"], ["aua e te fefe i alu ifo i Aikupito,", "fear not to go down into Egypt;"], ["auā ou te faia oe ma nuu tele.", "for I will there make of thee a great nation:"]]},
  {num:4,words:[["O a'u nei ta te o ifo ma oe i Aikupito,", "I will go down with thee into Egypt;"], ["ou te toe aveina ae ai foi ia te oe;", "and I will also surely bring thee up again:"], ["e tuu foi e Iosefa ona lima i luga ou mata.", "and Joseph shall put his hand upon thine eyes."]]},
  {num:5,words:[["Ona tulai atu lea o Iakopo i Peresepa,", "And Jacob rose up from Beer-sheba:"], ["ua avea foi e atalii o Isaraelu lo latou tamā o Iakopo,", "and the sons of Israel carried Jacob their father,"], ["ma o latou tama iti,", "and their little ones, and their wives,"], ["ma a latou avā i fata faataavalevale na aauina mai e Farao e ave ai o ia.", "in the wagons which Pharaoh had sent to carry him."]]},
  {num:6,words:[["Ua latou avea foi a latou manu ma a latou oloa sa maua e i latou i le nuu o Kanana,", "And they took their cattle, and their goods,"], ["i loo ua latou oo atu i Aikupito,", "which they had gotten in the land of Canaan, and came into Egypt,"], ["o Iakopo atoa uma ma ana fanau faatasi ma ia;", "Jacob, and all his seed with him:"]]},
  {num:7,words:[["o ona atalii ma atalii o ona atalii faatasi ma ia,", "His sons,"], ["o ona afafine foi atoa ma afafine o ona atalii,", "and his sons' sons with him,"], ["ma lana fanau uma lava,", "his daughters, and his sons' daughters,"], ["ua latou o atu faatasi ma ia i Aikupito.", "and all his seed brought he with him into Egypt."]]},
  {num:8,words:[["O igoa nei o atalii o Isaraelu o e na o atu i Aikupito,", "And these are the names of the children of Israel,"], ["o Iakopo ma ona atalii;", "which came into Egypt,"], ["o le ulumatua a Iakopo o Reupena;", "Jacob and his sons: Reuben,"], ["o atalii o Reupena;", "Jacob's firstborn."]]},
  {num:9,words:[["o Enoka,", "And the sons of Reuben;"], ["ma Falu,", "Hanoch,"], ["ma Esarona,", "and Phallu, and Hezron,"], ["atoa ma Karame.", "and Carmi."]]},
  {num:10,words:[["O atalii foi o Simeona;", "And the sons of Simeon;"], ["o Iemuelu,", "Jemuel,"], ["ma Iaminu,", "and Jamin,"], ["ma Oata, ma Iakinu,", "and Ohad,"], ["ma Soaro,", "and Jachin,"], ["atoa ma Saulo,", "and Zohar,"], ["o le tama lea a le fafine Kanana.", "and Shaul the son of a Canaanitish woman."]]},
  {num:11,words:[["O atalii foi o Levi;", "And the sons of Levi;"], ["o Keresoma,", "Gershon,"], ["o Koato,", "Kohath,"], ["atoa ma Merari.", "and Merari."]]},
  {num:12,words:[["O atalii foi o Iuta;", "And the sons of Judah;"], ["o Eru, ma Onani,", "Er,"], ["ma Sila,", "and Onan,"], ["ma Faresa,", "and Shelah,"], ["atoa ma Sera;", "and Pharez,"], ["(a ua oti Eru ma Onani i le nuu o Kanana; ) o atalii o Faresa;", "and Zerah:"], ["o Esarona ma Hamulu.", "but Er and Onan died in the land of Canaan. And the sons of Pharez were Hezron and Hamul."]]},
  {num:13,words:[["O atalii o Isakara;", "And the sons of Issachar;"], ["o Tulaga,", "Tola,"], ["ma Pua,", "and Phuvah,"], ["ma Iopu,", "and Job,"], ["atoa ma Semarona.", "and Shimron."]]},
  {num:14,words:[["O atalii foi o Sepulona;", "And the sons of Zebulun;"], ["o Seretu,", "Sered,"], ["ma Aluna,", "and Elon,"], ["ma Ialelu.", "and Jahleel."]]},
  {num:15,words:[["O tama tane lava i latou a Lea,", "These be the sons of Leah,"], ["na ia fanau ia Iakopo i Patanarama,", "which she bare unto Jacob in Padan-aram,"], ["atoa ma lona afafine o Tina;", "with his daughter Dinah:"], ["o ona atalii atoa ia ma ona afafine ua toatolugafulu ma le toatolu.", "all the souls of his sons and his daughters were thirty and three."]]},
  {num:16,words:[["O atalii o Kato;", "And the sons of Gad;"], ["o Sefiono,", "Ziphion,"], ["ma Haki,", "and Haggi,"], ["ma Suni,", "Shuni,"], ["ma Eseponu,", "and Ezbon,"], ["ma Eri,", "Eri,"], ["ma Aroti,", "and Arodi,"], ["atoa ma Areli.", "and Areli."]]},
  {num:17,words:[["O atalii foi o Asera;", "And the sons of Asher;"], ["o Iemina,", "Jimnah,"], ["ma Iesiva,", "and Ishuah,"], ["ma Iesivi,", "and Isui,"], ["atoa ma Peria,", "and Beriah, and Serah their sister:"], ["i le ma lo latou tuafafine o Sera;", "and the sons of Beriah;"], ["o atalii foi o Peria;", "Heber,"], ["o Kaveru ma Mekielu.", "and Malchiel."]]},
  {num:18,words:[["O tama nei a Selepa,", "These are the sons of Zilpah,"], ["o le na avatua e Lapana i lona afafine o Lea,", "whom Laban gave to Leah his daughter,"], ["na ia fanau mai i latou ia Iakopo,", "and these she bare unto Jacob,"], ["o tama e toatinoagafulu ma le toaono.", "even sixteen souls."]]},
  {num:19,words:[["O tama a Rasela,", "The sons of Rachel Jacob's wife;"], ["le avā a Iakopo;", "Joseph,"], ["o Iosefa ma Peniamina.", "and Benjamin."]]},
  {num:20,words:[["Na fanau foi ia Iosefa i le nuu o Aikupito, o e na fanau ia te ia ia Asenati o le afafine lea o Potifere le ositaulaga i Onu;", "And unto Joseph in the land of Egypt were born Manasseh and Ephraim,"], ["o Manase ma Efaraima.", "which Asenath the daughter of Poti-pherah priest of On bare unto him."]]},
  {num:21,words:[["O atalii foi o Peniamina;", "And the sons of Benjamin were Belah,"], ["o Pela,", "and Becher,"], ["ma Pekaru,", "and Ashbel,"], ["ma Asepelu,", "Gera,"], ["o Kira, ma Naamanu,", "and Naaman,"], ["o Aki,", "Ehi,"], ["ma Roso,", "and Rosh,"], ["o Mepimu,", "Muppim,"], ["ma Hupimo,", "and Huppim,"], ["atoa ma Aratu.", "and Ard."]]},
  {num:22,words:[["O tama tane ia a Rasela na ia fanau ia Iakopo,", "These are the sons of Rachel,"], ["o i latou atoa,", "which were born to Jacob:"], ["o tagata e toatinoagafulu ma le toafa.", "all the souls were fourteen."]]},
  {num:23,words:[["O le atalii foi o Tanu;", "And the sons of Dan;"], ["o Husimo.", "Hushim."]]},
  {num:24,words:[["O atalii o Nafatali;", "And the sons of Naphtali;"], ["o Iasielu,", "Jahzeel,"], ["ma Kuni,", "and Guni,"], ["ma Iesaru,", "and Jezer,"], ["atoa ma Selimo.", "and Shillem."]]},
  {num:25,words:[["O tama nei a Pila,", "These are the sons of Bilhah,"], ["o le na avatua e Lapana i lona afafine o Rasela,", "which Laban gave unto Rachel his daughter,"], ["na ia fanau mai i latou ia Iakopo,", "and she bare these unto Jacob:"], ["o ona atoa ia o tama e toafitu.", "all the souls were seven."]]},
  {num:26,words:[["O tagata uma na o mai ma Iakopo i Aikupito,", "All the souls that came with Jacob into Egypt,"], ["e na tutupu mai ia te ia,", "which came out of his loins,"], ["a e le faitaulia avā a atalii o Iakopo,", "besides Jacob's sons' wives,"], ["o ona atoa o tagata uma e toaonogafulu ma le toaono.", "all the souls were threescore and six;"]]},
  {num:27,words:[["O atalii o Iosefa e na fanau ia te ia i Aikupito,", "And the sons of Joseph, which were born him in Egypt,"], ["o tama e toalua;", "were two souls: all the souls of the house of Jacob,"], ["o tagata atoa uma o le aiga o Iakopo e na o mai i Aikupito e toafitugafulu lava i latou.", "which came into Egypt, were threescore and ten."]]},
  {num:28,words:[["Ua ia auina atu foi Iuta e muamua atu ia te ia ia Iosefa,", "And he sent Judah before him unto Joseph,"], ["ina ia faasino e ia ia te ia o Kosena;", "to direct his face unto Goshen;"], ["ona oo atu lea o i latou i le laueleele o Kosena.", "and they came into the land of Goshen."]]},
  {num:29,words:[["Ona sauni lea e Iosefa o lona nofoa faataavalevale,", "And Joseph made ready his chariot,"], ["ua alu ae foi i Kosena la te fetaiai ai ma lona tamā o Isaraelu;", "and went up to meet Israel his father,"], ["ua na iloa atu ia te ia,", "to Goshen, and presented himself unto him;"], ["ona fusi ai lea ia te ia,", "and he fell on his neck,"], ["ma tagi pea lava i lona ua.", "and wept on his neck a good while."]]},
  {num:30,words:[["Ona fai atu lea o Isaraelu ia Iosefa,", "And Israel said unto Joseph,"], ["Ia a'u oti nei lava,", "Now let me die,"], ["ina ua ou iloa atu ou mata,", "since I have seen thy face,"], ["auā ua e ola pea lava.", "because thou art yet alive."]]},
  {num:31,words:[["Ona fai atu lea o Iosefa i ona uso ma le aiga o lona tamā,", "And Joseph said unto his brethren, and unto his father's house,"], ["Ou te alu ae ma ou ta'u atu ia Farao,", "I will go up, and shew Pharaoh,"], ["ou te fai atu ia te ia,", "and say unto him, My brethren, and my father's house,"], ["Ua o mai ia te au o'u uso ma le aiga o lo'u tamā o e sa i le nuu o Kanana;", "which were in the land of Canaan, are come unto me;"]]},
  {num:32,words:[["o leoleo mamoe i latou,", "And the men are shepherds,"], ["auā o tagata faga manu i latou;", "for their trade hath been to feed cattle;"], ["ua au mai a latou lafu mamoe,", "and they have brought their flocks,"], ["ma a latou povi,", "and their herds,"], ["ma mea uma lava o loo ia i latou.", "and all that they have."]]},
  {num:33,words:[["A aami mai foi Farao ia te outou,", "And it shall come to pass,"], ["ma fesili ia te outou,", "when Pharaoh shall call you, and shall say,"], ["Se a lo outou faiva?", "What is your occupation?"]]},
  {num:34,words:[["Ona outou fai atu ai lea,", "That ye shall say,"], ["O tagata faga manu au auauna talu ina o taulelea i matou ua oo mai i ona po nei,", "Thy servants' trade hath been about cattle from our youth even until now,"], ["o i matou atoa ma o matou tamā;", "both we,"], ["tou te faapea atu ,", "and also our fathers:"], ["ina ia nofo outou i le laueleele o Kosena;", "that ye may dwell in the land of Goshen;"], ["auā ua inosia lava e le nuu o Aikupito o leoleo mamoe uma lava.", "for every shepherd is an abomination unto the Egyptians."]]},
];
renderVerseSet(gen_ch_46_Verses, 'gen-ch46-verses');

var gen_ch_47_Verses = [
  {num:1,words:[["Ona alu ane lea o Iosefa ia Farao ma na ta'u atu ia te ia,", "Then Joseph came and told Pharaoh,"], ["o loo faapea atu,", "and said,"], ["Ua o mai mai le nuu o Kanana o lo'u tamā,", "My father and my brethren,"], ["ma o'u uso,", "and their flocks,"], ["ma a latou lafu mamoe,", "and their herds, and all that they have,"], ["ma a latou povi,", "are come out of the land of Canaan;"], ["ma mea uma lava o loo ia i latou;", "and,"], ["faauta foi,", "behold,"], ["o loo i le laueleele o Kosena i latou.", "they are in the land of Goshen."]]},
  {num:2,words:[["Ua ave foi e ia ni ona uso o tagata e toalima,", "And he took some of his brethren, even five men,"], ["ma tuu atu i latou i luma o Farao.", "and presented them unto Pharaoh."]]},
  {num:3,words:[["Ona fai mai lea o Farao i ona uso,", "And Pharaoh said unto his brethren,"], ["Se a ea lo outou faiva? Ona tali atu lea o i latou ia Farao,", "What is your occupation? And they said unto Pharaoh,"], ["O leoleo mamoe au nei auauna,", "Thy servants are shepherds, both we,"], ["o i matou nei atoa ma o matou tamā.", "and also our fathers."]]},
  {num:4,words:[["Ua latou fai atu foi ia Farao,", "They said moreover unto Pharaoh,"], ["Ua matou o mai,", "For to sojourn in the land are we come;"], ["matou te āumau i le nuu nei ,", "for thy servants have no pasture for their flocks;"], ["auā ua leai ni mea e faga a'i lafu mamoe a au auauna,", "for the famine is sore in the land of Canaan:"], ["ina ua velavela le oge i le nuu o Kanana;", "now therefore,"], ["o lenei,", "we pray thee,"], ["pe te finagalo ia nonofo au auauna i le laueleele o Kosena.", "let thy servants dwell in the land of Goshen."]]},
  {num:5,words:[["Ona fai mai lea o Farao ia Iosefa,", "And Pharaoh spake unto Joseph,"], ["o loo faapea mai,", "saying,"], ["Ua o mai ia te oe lou tamā ma ou uso;", "Thy father and thy brethren are come unto thee:"]]},
  {num:6,words:[["o loo i ou luma lava le laueleele o Aikupito;", "The land of Egypt is before thee;"], ["ia e tuuina atu lou tamā ma ou uso e nonofo i le fanua e sili ona lelei;", "in the best of the land make thy father and brethren to dwell;"], ["ia nonofo i latou i le laueleele o Kosenai afai foi ua e iloa ni o latou ua malolosi,", "in the land of Goshen let them dwell: and if thou knowest any men of activity among them,"], ["ia fai i latou ma leoleo sili i a'u manu.", "then make them rulers over my cattle."]]},
  {num:7,words:[["Ona au mai lea e Iosefa o lona tamā o Iakopo ma ua tuu atu ia te ia i luma o Farao;", "And Joseph brought in Jacob his father, and set him before Pharaoh:"], ["ona faamanuia lea e Iakopo ia Farao.", "and Jacob blessed Pharaoh."]]},
  {num:8,words:[["Ona fai mai lea o Farao ia Iakopo,", "And Pharaoh said unto Jacob,"], ["E fia ea tausaga o lou olaga?", "How old art thou?"]]},
  {num:9,words:[["Ona fai atu lea o Iakopo ia Farao,", "And Jacob said unto Pharaoh,"], ["O tausaga ua ou āumau ai,", "The days of the years of my pilgrimage are an hundred and thirty years:"], ["o tausaga ia e tasi le selau ma le tolugafulu; ua itiiti ma ua leaga tausaga o lo'u nei olaga,", "few and evil have the days of the years of my life been,"], ["e lei oo i tausaga o olaga o o'u tamā i o latou aso na latou āumau ai.", "and have not attained unto the days of the years of the life of my fathers in the days of their pilgrimage."]]},
  {num:10,words:[["Ona faamanuia lea e Iakopo ia Farao,", "And Jacob blessed Pharaoh,"], ["ona alu ese lea o ia i luma o Farao.", "and went out from before Pharaoh."]]},
  {num:11,words:[["Ona tuu atu lea e Iosefa le nuu e mau ai lona tamā ma ona uso,", "And Joseph placed his father and his brethren,"], ["ma na avatu ai e fai mo latou i le nuu o Aikupito i le fanua ua sili ona lelei,", "and gave them a possession in the land of Egypt,"], ["o le nuu o Ramese;", "in the best of the land, in the land of Rameses,"], ["faapei ona poloai i ai o Farao.", "as Pharaoh had commanded."]]},
  {num:12,words:[["Ua fagaina foi e Iosefa lona tamā,", "And Joseph nourished his father, and his brethren,"], ["ma ona uso,", "and all his father's household,"], ["ma le aiga atoa uma o lona tamā i le mea e 'ai ua oo lava i o latou tama iti.", "with bread, according to their families."]]},
  {num:13,words:[["Sa leai foi sina mea e 'ai i le nuu atoa,", "And there was no bread in all the land;"], ["auā ua matuā velavela le oge,", "for the famine was very sore,"], ["ua lailoa foi le nuu o Aikupito ma le nuu o Kanana ona o le oge.", "so that the land of Egypt and all the land of Canaan fainted by reason of the famine."]]},
  {num:14,words:[["Ona faapotopotoina lea e Iosefa o tupe uma lava na maua i le nuu o Aikupito ma le nuu o Kanana mo le saito na faatauina e i latou;", "And Joseph gathered up all the money that was found in the land of Egypt, and in the land of Canaan,"], ["ua ave foi e Iosefa o tupe i le fale o Farao.", "for the corn which they bought: and Joseph brought the money into Pharaoh's house."]]},
  {num:15,words:[["Ua uma foi tupe i le nuu o Aikupito ma le nuu o Kanana,", "And when money failed in the land of Egypt,"], ["ona o ane lea o Aikupito uma ia Iosefa,", "and in the land of Canaan,"], ["ua faapea mai,", "all the Egyptians came unto Joseph, and said,"], ["Ia e au mai ia te i matou ni mea e 'ai. Ai lava a matou oti i ou luma,", "Give us bread:"], ["auā ua uma tupe.", "for why should we die in thy presence? for the money faileth."]]},
  {num:16,words:[["Ona fai atu lea o Iosefa,", "And Joseph said,"], ["Ina au mai ia a outou manu,", "Give your cattle;"], ["ou te faatauina a outou manu i mea e 'ai mā outou,", "and I will give you for your cattle,"], ["pe afai ua uma tupe.", "if money fail."]]},
  {num:17,words:[["Ona latou avane lea a latou manu ia Iosefa;", "And they brought their cattle unto Joseph:"], ["ona avatu lea e Iosefa ia te i latou o mea e 'ai e faatau a'i solofanua,", "and Joseph gave them bread in exchange for horses,"], ["ma lafu mamoe,", "and for the flocks,"], ["ma lafu povi,", "and for the cattle of the herds,"], ["atoa ma asini;", "and for the asses:"], ["na ia fagaina foi i latou i lea tausaga o le totogi lea o a latou lafu uma.", "and he fed them with bread for all their cattle for that year."]]},
  {num:18,words:[["Ua mavae foi lea tausaga,", "When that year was ended,"], ["ona o ane lea o i latou ia te ia i lona lua o tausaga,", "they came unto him the second year,"], ["ma latou fai mai ia te ia,", "and said unto him,"], ["Matou te le nanā i lo matou alii,", "We will not hide it from my lord,"], ["ua uma tupe;", "how that our money is spent; my lord also hath our herds of cattle;"], ["o i lo matou alii foi a matou lafu manu;", "there is not ought left in the sight of my lord,"], ["ua le toe lava sina mea ia i matou i luma o lo matou alii,", "but our bodies,"], ["ua na o matou tino ma o matou fanua.", "and our lands:"]]},
  {num:19,words:[["Ai lava a matou oti i ou luma,", "Wherefore shall we die before thine eyes,"], ["o i matou lava,", "both we and our land? buy us and our land for bread,"], ["a e tuufua lo matou fanua. Ia e faatauina atu i matou ma lo matou fanua i mea e 'ai,", "and we and our land will be servants unto Pharaoh:"], ["ona fai lea o i matou ma auauna a Farao,", "and give us seed,"], ["o i matou ma lo matou fanua;", "that we may live,"], ["ma ia e foaiina mai ni mea e toto ina ia ola i matou,", "and not die,"], ["ne'i oti i matou a e le āina le fanua.", "that the land be not desolate."]]},
  {num:20,words:[["Ona faatauina lea e Iosefa le fanua uma lava o Aikupito mo Farao;", "And Joseph bought all the land of Egypt for Pharaoh;"], ["auā na faatauina atu e Aikupito e taitoatasi ma lona fanua;", "for the Egyptians sold every man his field,"], ["auā sa manumalo le oge ia i latou;", "because the famine prevailed over them:"], ["i le ua avea le fanua mo Farao.", "so the land became Pharaoh's."]]},
  {num:21,words:[["O le nuu foi na aumaia i latou e ia i aai,", "And as for the people,"], ["e gata mai i le tasi tuaoi o Aikupito e oo atu lava i le tasi tuaoi.", "he removed them to cities from one end of the borders of Egypt even to the other end thereof."]]},
  {num:22,words:[["Na o fanua o le au ositaulaga,", "Only the land of the priests bought he not;"], ["e lei faatauina e ia;", "for the priests had a portion assigned them of Pharaoh,"], ["auā sa i ai i ositaulaga o le vaega o mea e 'ai mai ia Farao; na latou aai foi i o latou vaega o mea e 'ai na foaiina atu ia i latou e Farao;", "and did eat their portion which Pharaoh gave them:"], ["o le mea lea latou te lei faatauina ai o latou fanua.", "wherefore they sold not their lands."]]},
  {num:23,words:[["Ona fai atu lea o Iosefa i le nuu,", "Then Joseph said unto the people,"], ["Faauta,", "Behold,"], ["ua ou faatauina mai outou i le asō atoa ma outou fanua ma Farao;", "I have bought you this day and your land for Pharaoh:"], ["faauta,", "lo,"], ["o le saito lenei ma outou,", "here is seed for you,"], ["tou te luluina i le fanua.", "and ye shall sow the land."]]},
  {num:24,words:[["A oo ina tupu,", "And it shall come to pass in the increase,"], ["tou te avatua ia Farao o lona vaega e lima;", "that ye shall give the fifth part unto Pharaoh,"], ["a o vaega e fa ua totoe e a outou lava ia,", "and four parts shall be your own, for seed of the field,"], ["e fai ma saito e lulu ma mea e 'ai mā outou,", "and for your food,"], ["atoa ma i latou ua i o outou aiga,", "and for them of your households,"], ["ma mea e 'ai ma a outou fanau.", "and for food for your little ones."]]},
  {num:25,words:[["Ona latou tali mai lea,", "And they said,"], ["Ua e faaola mai lava ia te i matou;", "Thou hast saved our lives:"], ["ia alofagia i matou e lo matou alii,", "let us find grace in the sight of my lord,"], ["e fai foi i matou ma auauna a Farao.", "and we will be Pharaoh's servants."]]},
  {num:26,words:[["Ua fai ai foi lea e Iosefa ma tulafono i le nuu o Aikupito ua oo mai lava i ona po nei,", "And Joseph made it a law over the land of Egypt unto this day,"], ["ia avatu ia Farao le vaega e lima;", "that Pharaoh should have the fifth part; except the land of the priests only,"], ["na o le fanua lava o ositaulaga ua le faia lea mo Farao.", "which became not Pharaoh's."]]},
  {num:27,words:[["Ona nofo lea o sa Isaraelū i le nuu o Aikupito i le laueleele o Kosena,", "And Israel dwelt in the land of Egypt,"], ["ma latou fai fanua ai;", "in the country of Goshen;"], ["ua uluola foi i latou,", "and they had possessions therein, and grew,"], ["ua faatoateleina lava.", "and multiplied exceedingly."]]},
  {num:28,words:[["Sa nofo Iakopo i le nuu o Aikupito i tausaga e sefulu ma le fitu o aso foi o ona tausaga uma na ola ai Iakopo,", "And Jacob lived in the land of Egypt seventeen years:"], ["ua tasi le selau ma le fagafulu ma tausaga e fitu.", "so the whole age of Jacob was an hundred forty and seven years."]]},
  {num:29,words:[["Ua tāu lata mai foi aso e maliu ai Isaraelu,", "And the time drew nigh that Israel must die:"], ["ona aami lea e ia o lona atalii o Iosefa,", "and he called his son Joseph, and said unto him,"], ["ua faapea atu ia te ia,", "If now I have found grace in thy sight,"], ["Afai ua alofagia a'u e oe,", "put, I pray thee,"], ["ia e sulu mai lou lima i lalo o lo'u aloivae,", "thy hand under my thigh,"], ["ma ia e alofa mai,", "and deal kindly and truly with me;"], ["ma faamaoni mai ia te au,", "bury me not, I pray thee,"], ["aua lava e te tanu ia te au i Aikupito;", "in Egypt:"]]},
  {num:30,words:[["a ou te taoto faatasi ma o'u tamā,", "But I will lie with my fathers,"], ["ia e avae a'u ai Aikupito,", "and thou shalt carry me out of Egypt,"], ["ma e tanu ia te au i lo latou tuugamau. Ona tali mai lea o ia ia te ia,", "and bury me in their buryingplace. And he said,"], ["Ou te faia lava e pei ona e fai mai ai.", "I will do as thou hast said."]]},
  {num:31,words:[["Ona fai atu ai lea o ia, Ia e tauto mai ia te au;", "And he said,"], ["ona tauto ai lea o ia ia te ia; ona ifo ai lea o Isaraelu i le ulu o le moega.", "Swear unto me. And he sware unto him. And Israel bowed himself upon the bed's head."]]},
];
renderVerseSet(gen_ch_47_Verses, 'gen-ch47-verses');

var gen_ch_48_Verses = [
  {num:1,words:[["E mulimuli ane foi i ia mea,", "And it came to pass after these things,"], ["ua tala atu ia Iosefa,", "that one told Joseph,"], ["Faauta,", "Behold,"], ["ua ma'i lou tamā;", "thy father is sick:"], ["ona ave ai lea e ia ona atalii e toalua,", "and he took with him his two sons,"], ["o Manase ma Efaraima.", "Manasseh and Ephraim."]]},
  {num:2,words:[["Ona ta'u atu lea ia Iakopo,", "And one told Jacob,"], ["o loo faapea atu,", "and said,"], ["Faauta,", "Behold,"], ["o loo sau ia te oe lou atalii o Iosefa;", "thy son Joseph cometh unto thee:"], ["ona faamalosi lea o Isaraelu,", "and Israel strengthened himself,"], ["ua nofo i luga i le moega.", "and sat upon the bed."]]},
  {num:3,words:[["Ona fai atu lea o Iakopo ia Iosefa,", "And Jacob said unto Joseph,"], ["Na faaali mai ia te au o le Atua e ona le malosi uma lava i Lusa i le nuu o Kanana,", "God Almighty appeared unto me at Luz in the land of Canaan,"], ["ma na faamanuia mai ia te au.", "and blessed me,"]]},
  {num:4,words:[["Na ia fetalai mai ia te au,", "And said unto me,"], ["Faauta,", "Behold,"], ["ou te faauluolaina oe, ma ou faatoateleina oe,", "I will make thee fruitful,"], ["ou te faia foi oe ma faapotopotoga o nuu;", "and multiply thee,"], ["ou te avatu foi lenei nuu i lau fanau pe a mavae atu oe,", "and I will make of thee a multitude of people;"], ["e fai mo latou e faavavau.", "and will give this land to thy seed after thee for an everlasting possession."]]},
  {num:5,words:[["O lenei foi,", "And now thy two sons,"], ["o ou atalii e toalua na fanau ia te oe i le nuu o Aikupito,", "Ephraim and Manasseh,"], ["a o lei sau o a'u ia te oe i Aikupito,", "which were born unto thee in the land of Egypt before I came unto thee into Egypt,"], ["e o'u lava i laua,", "are mine;"], ["o Efaraima ma Manase,", "as Reuben and Simeon,"], ["e fai mo a'u e faapei o Reupena ma Simeona.", "they shall be mine."]]},
  {num:6,words:[["O lau fanau foi e te fanaua e mulimuli ane ia i laua,", "And thy issue,"], ["e ou i latou,", "which thou begettest after them, shall be thine,"], ["e ta'ua i latou i le igoa o latou uso i o la tofi.", "and shall be called after the name of their brethren in their inheritance."]]},
  {num:7,words:[["O a'u foi,", "And as for me,"], ["na ou sau nai Patana,", "when I came from Padan,"], ["ona oti ai lea o Rasela o latalata ane ia te au i le nuu o Kanana,", "Rachel died by me in the land of Canaan in the way,"], ["i le ala ina ua tali oo i Efarata,", "when yet there was but a little way to come unto Ephrath:"], ["na ou tanumia o ia i lea mea i le ala i Efarata,", "and I buried her there in the way of Ephrath;"], ["o Peteleema lava lea.", "the same is Beth-lehem."]]},
  {num:8,words:[["Ona iloa atu lea e Isaraelu i atalii o Iosefa,", "And Israel beheld Joseph's sons,"], ["ua faapea ane,", "and said,"], ["O ai ea i laua nei?", "Who are these?"]]},
  {num:9,words:[["Ona tali atu lea o Iosefa i lona tamā,", "And Joseph said unto his father,"], ["O o'u atalii lava i laua nei ua foaiina mai ia te au e le Atua i lenei nuu;", "They are my sons, whom God hath given me in this place. And he said,"], ["ona ia fai atu lea,", "Bring them,"], ["Ina au mai ia ia te au,", "I pray thee, unto me,"], ["ou te famanuia ia te i laua.", "and I will bless them."]]},
  {num:10,words:[["Sa faasegosego foi mata o Isaraelu, auā ua toeaina,", "Now the eyes of Israel were dim for age,"], ["sa le mailoa lelei;", "so that he could not see. And he brought them near unto him;"], ["ona ia faalatalataina lea o i laua ia te ia,", "and he kissed them,"], ["ona taufeasogi lea o ia ma i laua, ma na fusi ia i laua.", "and embraced them."]]},
  {num:11,words:[["Ona fai atu lea o Isaraelu ia Iosefa,", "And Israel said unto Joseph, I had not thought to see thy face:"], ["Fa ita ou te le toe iloa atu ia te oe,", "and,"], ["faauta foi ua faailoa mai e le Atua ia te au au fanau.", "lo, God hath shewed me also thy seed."]]},
  {num:12,words:[["Ona aumaia lea e Iosefa o i laua nai le va o ona vae,", "And Joseph brought them out from between his knees,"], ["ua ifo toele foi o ia.", "and he bowed himself with his face to the earth."]]},
  {num:13,words:[["Ona avea lea o i laua e Iosefa,", "And Joseph took them both,"], ["o Efaraima i lona lima taumatau e feagai ma le lima tauagavale o Isaraelu,", "Ephraim in his right hand toward Israel's left hand,"], ["o Manase foi i lona lima tauagavale e feagai ma le lima taumatau o Isaraelu,", "and Manasseh in his left hand toward Israel's right hand,"], ["ona faalatalata atu lea o i laua ia te ia.", "and brought them near unto him."]]},
  {num:14,words:[["Ona faaloaloa atu lea e Isaraelu o lona lima taumatau,", "And Israel stretched out his right hand,"], ["ma faaee ai i le ulu o Efaraima,", "and laid it upon Ephraim's head,"], ["a o le uii lava ia;", "who was the younger,"], ["a ua faaee lona lima tauagavale i le ulu o Manase,", "and his left hand upon Manasseh's head,"], ["ua na fai faautauta i ona lima,", "guiding his hands wittingly;"], ["auā o Manase o le ulumatua lava lea.", "for Manasseh was the firstborn."]]},
  {num:15,words:[["Ona faamanuia atu lea o ia ia Iosefa ua faapea atu ai,", "And he blessed Joseph,"], ["O le Atua lava o le na savali ai i ona luma o'u tamā o Aperaamo ma Isaako,", "and said,"], ["o le Atua lava o le na fagaina a'u talu ina fanau o a'u,", "God, before whom my fathers Abraham and Isaac did walk,"], ["ua oo mai lava i le aso nei;", "the God which fed me all my life long unto this day,"]]},
  {num:16,words:[["o le Agelu lava o le na laveaiina mai a'u ai le leaga uma lava,", "The Angel which redeemed me from all evil,"], ["ia faamanuia atu lava o ia i tama nei;", "bless the lads;"], ["ia faaigoa foi i ai i lo'u nei igoa ma igoa o o'u tamā o Aperaamo ma Isaako,", "and let my name be named on them, and the name of my fathers Abraham and Isaac;"], ["ma ia matuā faatoateleina i laua i le lalolagi.", "and let them grow into a multitude in the midst of the earth."]]},
  {num:17,words:[["Ua iloa e Iosefa,", "And when Joseph saw that his father laid his right hand upon the head of Ephraim,"], ["ua faaee e lona tamā lona lima taumatau i le ulu o Efaraima,", "it displeased him:"], ["ua leaga lea ia te ia,", "and he held up his father's hand,"], ["ona sii lea e ia i luga le lima o lona tamā ina ia avea nai le ulu o Efaraima i luga o le ulu o Manase.", "to remove it from Ephraim's head unto Manasseh's head."]]},
  {num:18,words:[["Ua faapea atu foi Iosefa i lona tamā,", "And Joseph said unto his father,"], ["Lo'u tamā e,", "Not so,"], ["aua le faapea,", "my father:"], ["auā o le ulumatua lenei;", "for this is the firstborn;"], ["se'i faaee lou lima taumatau i luga i lona ulu.", "put thy right hand upon his head."]]},
  {num:19,words:[["A ua le mafai lona tamā,", "And his father refused,"], ["ua ia fai mai,", "and said,"], ["Ua ou iloa,", "I know it,"], ["lo'u atalii e,", "my son,"], ["ua ou iloa lava,", "I know it:"], ["e avea foi o ia ma nuu,", "he also shall become a people,"], ["o ia foi lava e faatoateleina;", "and he also shall be great:"], ["a e peitai e sili lava lona uso aupito itiiti ia te ia,", "but truly his younger brother shall be greater than he,"], ["e avea foi ana fanau ma nuu e tele.", "and his seed shall become a multitude of nations."]]},
  {num:20,words:[["Ona faamanuia lea e ia ia i laua i lea lava aso,", "And he blessed them that day,"], ["ua faapea ane,", "saying,"], ["O oe e fai ai faamanuia e Isaraelu,", "In thee shall Israel bless,"], ["e faapea,", "saying,"], ["Ia faatusaina oe e le Atua ia Efaraima ma Manase;", "God make thee as Ephraim and as Manasseh:"], ["ua ia tofia Efaraima ia sili ia Manase.", "and he set Ephraim before Manasseh."]]},
  {num:21,words:[["Ona fai atu lea o Isaraelu ia Iosefa,", "And Israel said unto Joseph,"], ["Faauta,", "Behold,"], ["o a'u nei o le a a'u oti,", "I die:"], ["a e ia te outou pea le Atua,", "but God shall be with you,"], ["e faafoisia e ia outou i le nuu o outou tamā.", "and bring you again unto the land of your fathers."]]},
  {num:22,words:[["O a'u foi, ua ou avatu ia te oe le tasi tofi e sili i ou uso,", "Moreover I have given to thee one portion above thy brethren,"], ["o le mea na ou faoa nai le lima o sa Amorī i la'u pelu ma la'u aufana.", "which I took out of the hand of the Amorite with my sword and with my bow."]]},
];
renderVerseSet(gen_ch_48_Verses, 'gen-ch48-verses');

var gen_ch_49_Verses = [
  {num:1,words:[["Ona aami lea e Iakopo ona atalii,", "And Jacob called unto his sons,"], ["ma na faapea atu,", "and said,"], ["Faapotopoto mai ia outou,", "Gather yourselves together,"], ["a a'u faaali atu ia te outou o mea e oo ia te outou i aso amuli.", "that I may tell you that which shall befall you in the last days."]]},
  {num:2,words:[["Faapotopoto mai ia,", "Gather yourselves together,"], ["ma faalogologo mai outou atalii o Iakopo;", "and hear, ye sons of Jacob;"], ["ina faalogologo mai ia i lo outou tamā o Isaraelu.", "and hearken unto Israel your father."]]},
  {num:3,words:[["O Reupena,", "Reuben,"], ["o la'u ulumatua lava oe,", "thou art my firstborn,"], ["o lo'u malosi,", "my might,"], ["ma le na amata mai ai lo'u mamalu,", "and the beginning of my strength,"], ["o le ua silisili ona mamalu,", "the excellency of dignity,"], ["ua silisili ona malosi.", "and the excellency of power:"]]},
  {num:4,words:[["Ua e oso vale pei o le vai,", "Unstable as water,"], ["e le faasili lava oe;", "thou shalt not excel;"], ["auā na e alu ae i le moega o lou tamā,", "because thou wentest up to thy father's bed;"], ["i le ua leaga ia te oe;", "then defiledst thou it:"], ["na alu ae ia i lo'u moega.", "he went up to my couch."]]},
  {num:5,words:[["O Simeona ma Levi, o le uso i laua;", "Simeon and Levi are brethren;"], ["ua fai a laua pelu ma auupega e faasaua ai.", "instruments of cruelty are in their habitations."]]},
  {num:6,words:[["Aua ne'i usitai lo'u loto i la laua taupulepulega nanā;", "O my soul, come not thou into their secret;"], ["aua ne'i faatasi lo'u mamalu i lo laua potopotoga;", "unto their assembly, mine honour,"], ["auā na la fasioti le tagata i lo laua ita,", "be not thou united:"], ["o lo laua finau vale foi na la faapipili ai o vae o le povi.", "for in their anger they slew a man, and in their selfwill they digged down a wall."]]},
  {num:7,words:[["Ia fetuuina lo la ita ina ua silisili,", "Cursed be their anger, for it was fierce;"], ["mo lo la ita tele lava ina ua la finau vale ai;", "and their wrath,"], ["ou te vavaeina i laua i le nuu o Iakopo,", "for it was cruel:"], ["ou te faataapeapeina i laua i Isaraelu.", "I will divide them in Jacob, and scatter them in Israel."]]},
  {num:8,words:[["Oe na Iuta,", "Judah,"], ["e viia oe e ou uso;", "thou art he whom thy brethren shall praise:"], ["e oo lou lima i ua o e ita ia te oe;", "thy hand shall be in the neck of thine enemies;"], ["e ifo ia te oe le fanau a lou tamā.", "thy father's children shall bow down before thee."]]},
  {num:9,words:[["O le tamai leona Iuta;", "Judah is a lion's whelp:"], ["lo'u atalii e,", "from the prey,"], ["na e alu ae nai le mea na saeia;", "my son,"], ["na ia taoto,", "thou art gone up: he stooped down,"], ["na ia faapuga pei o le leona,", "he couched as a lion,"], ["e pei o se leona fafine;", "and as an old lion;"], ["o ai se na te faalili ia te ia?", "who shall rouse him up?"]]},
  {num:10,words:[["E le avea le tootoo ia Iuta,", "The sceptre shall not depart from Judah,"], ["po o le faipule ai ona vae seia maliu mai Sailo,", "nor a lawgiver from between his feet, until Shiloh come;"], ["e usiusitai foi atu nuu ia te ia.", "and unto him shall the gathering of the people be."]]},
  {num:11,words:[["O loo nonoa lana asini i le vine,", "Binding his foal unto the vine,"], ["ma lana tamai asini i le vine lelei;", "and his ass's colt unto the choice vine;"], ["o loo ta ona ofu i le uaina,", "he washed his garments in wine,"], ["ma lona ie pulupulu i le toto o le fua o le vine;", "and his clothes in the blood of grapes:"]]},
  {num:12,words:[["e mūmū ona mata i le uaina,", "His eyes shall be red with wine,"], ["e sisina ona nifo i le suasusu.", "and his teeth white with milk."]]},
  {num:13,words:[["O Sepulona e tu matafaga le mea e mau ai o ia;", "Zebulun shall dwell at the haven of the sea;"], ["e i ai foi o ia i le mea e tau ai vaa;", "and he shall be for an haven of ships;"], ["e oo foi lona tuaoi i Saitonu.", "and his border shall be unto Zidon."]]},
  {num:14,words:[["O Isakara e pei o le asini malosi o ia, o loo taoto i le va o avega e lua;", "Issachar is a strong ass couching down between two burdens:"]]},
  {num:15,words:[["ua iloa atu e ia le malologa ua lelei,", "And he saw that rest was good,"], ["ma le fanua ua matagofie,", "and the land that it was pleasant;"], ["ona tuuina atu lea o lona ua i le amoga,", "and bowed his shoulder to bear,"], ["ua fai foi ma pologa e fai taulaga.", "and became a servant unto tribute."]]},
  {num:16,words:[["E faamasino e Tanu lona nuu,", "Dan shall judge his people,"], ["pei o le tasi itu aiga o Isaraelu;", "as one of the tribes of Israel."]]},
  {num:17,words:[["e fai Tanu ma gata i le ala o le malo,", "Dan shall be a serpent by the way,"], ["o le gata feai i le ala,", "an adder in the path,"], ["e utia ai mulivae o le solofanua,", "that biteth the horse heels,"], ["e paū ai i tua lē tietie ai.", "so that his rider shall fall backward."]]},
  {num:18,words:[["Ieova e,", "I have waited for thy salvation,"], ["ua ou faamoemoe i le olataga mai ia te oe.", "O LORD."]]},
  {num:19,words:[["O Kato,", "Gad,"], ["e malo se 'au ia te ia; a o ia,", "a troop shall overcome him:"], ["e iu ina malo lava ia.", "but he shall overcome at the last."]]},
  {num:20,words:[["Mai ia Asera o mea lololo, o lana mea e 'ai lea;", "Out of Asher his bread shall be fat,"], ["o ia foi na te avatua o mea e faafiafia a'i tupu.", "and he shall yield royal dainties."]]},
  {num:21,words:[["O Nafatali o le aila ua tatalaina atu ia,", "Naphtali is a hind let loose:"], ["o le na te talatalaina atu i upu lelei.", "he giveth goodly words."]]},
  {num:22,words:[["O Iosefa o le la laau o ia e fua o le la laau e fua i tafatafa o le vaipuna;", "Joseph is a fruitful bough, even a fruitful bough by a well;"], ["e sosolo ona la i luga i le pa.", "whose branches run over the wall:"]]},
  {num:23,words:[["Na faatigaina o ia e i latou o e fanafana u;", "The archers have sorely grieved him,"], ["na latou fanafana atu ia te ia,", "and shot at him,"], ["ma ita ia te ia.", "and hated him:"]]},
  {num:24,words:[["A ua tumau pea le malosi o lana aufana,", "But his bow abode in strength,"], ["o ona lima foi ua faamalosia ia e aao o lē Malosi o Iakopo;", "and the arms of his hands were made strong by the hands of the mighty God of Jacob;"], ["o loo tupu mai ai foi le leoleo mamoe,", "(from thence is the shepherd, the stone of Israel:"], ["o le maa lea o Isaraelu;", ")"]]},
  {num:25,words:[["e a le Atua o lou tamā o le fesoasoani ia te oe,", "Even by the God of thy father, who shall help thee;"], ["o Lē e ona le malosi uma lava na te faamanuia oe i manuia mai le lagi i lugā,", "and by the Almighty, who shall bless thee with blessings of heaven above,"], ["ma manuia mai le mea loloto o loo i lalō,", "blessings of the deep that lieth under,"], ["o manuia o susu ma le manava;", "blessings of the breasts, and of the womb:"]]},
  {num:26,words:[["o manuia o lou tamā ua sili lava ia i manuia o o'u tupuga,", "The blessings of thy father have prevailed above the blessings of my progenitors unto the utmost bound of the everlasting hills:"], ["ua oo i le tuaoi lava o mauga o le vavau; e oo pea lava ia i luga o le ulu o Iosefa,", "they shall be on the head of Joseph,"], ["ma le tumuai o le na sili i ona uso.", "and on the crown of the head of him that was separate from his brethren."]]},
  {num:27,words:[["O Peniamina o le luko na te saeia;", "Benjamin shall ravin as a wolf:"], ["o le taeao e 'ai ai e ia le mea ua maua;", "in the morning he shall devour the prey,"], ["o le afiafi e vavaeina ai e ia o mea ua faoa.", "and at night he shall divide the spoil."]]},
  {num:28,words:[["O i latou atoa nei,", "All these are the twelve tribes of Israel:"], ["o itu aiga e sefulu ma le lua o Isaraelu;", "and this is it that their father spake unto them,"], ["o upu foi ia a lo latou tamā ia i latou, ua ia faamanuia ai foi i latou,", "and blessed them;"], ["e taitoatasi ma lona manuia ua ia faamanuia ai i latou.", "every one according to his blessing he blessed them."]]},
  {num:29,words:[["Ua fai atu foi o ia ia te i latou,", "And he charged them,"], ["o loo faapea atu ia te i latou,", "and said unto them,"], ["O le a faaopoopoina atu a'u i lo'u nuu;", "I am to be gathered unto my people:"], ["ia outou tanu lava a'u faatasi ma o'u tamā i le ana o loo i le fanua o Eferona o le sa Hetī;", "bury me with my fathers in the cave that is in the field of Ephron the Hittite,"]]},
  {num:30,words:[["o le ana lea o loo i le fanua o Makapelu,", "In the cave that is in the field of Machpelah,"], ["o loo i luma o Mamere,", "which is before Mamre,"], ["i le nuu o Kanana,", "in the land of Canaan,"], ["sa faatauina lea fanua e Aperaamo mai ia Eferona o le sa Hetī e fai ma tuugamau.", "which Abraham bought with the field of Ephron the Hittite for a possession of a buryingplace."]]},
  {num:31,words:[["O le mea lea na latou tanumia ai Aperaamo ma lana avā o Sara,", "There they buried Abraham and Sarah his wife;"], ["o le mea foi lea na latou tanumia ai Isaako ma lana avā o Repeka,", "there they buried Isaac and Rebekah his wife;"], ["o le mea foi lea na ou tanumia ai Lea.", "and there I buried Leah."]]},
  {num:32,words:[["O le faatauga o le la fanua atoa ma le ana o loo i ai, mai le fanauga a Heti lea.", "The purchase of the field and of the cave that is therein was from the children of Heth."]]},
  {num:33,words:[["Ua uma atu foi le mavaega a Iakopo i ona atalii,", "And when Jacob had made an end of commanding his sons,"], ["ona faapupuu ae lea ona vae i lona moega,", "he gathered up his feet into the bed,"], ["ona to lea o lana mānava,", "and yielded up the ghost,"], ["ua faaopoopoina o ia i lona nuu.", "and was gathered unto his people."]]},
];
renderVerseSet(gen_ch_49_Verses, 'gen-ch49-verses');

var gen_ch_50_Verses = [
  {num:1,words:[["Ona faapaū atu lea o Iosefa i fofoga o lona tamā,", "And Joseph fell upon his father's face,"], ["ua tagi ai i ona luga,", "and wept upon him,"], ["ma sogi ia te ia.", "and kissed him."]]},
  {num:2,words:[["Ona poloai lea o Iosefa i ana auauna fomai ia latou atualala i lona tamā;", "And Joseph commanded his servants the physicians to embalm his father:"], ["ona atualalaina lea o Isaraelu e fomai.", "and the physicians embalmed Israel."]]},
  {num:3,words:[["Ua atoa ona aso e fagafulu,", "And forty days were fulfilled for him;"], ["auā o loo faapea ona faaatoa o aso o e ua atualalaina;", "for so are fulfilled the days of those which are embalmed:"], ["ua tagi foi Aikupito ia te ia e fitugafulu ona aso.", "and the Egyptians mourned for him threescore and ten days."]]},
  {num:4,words:[["Ua mavae aso na taufaitagi ai,", "And when the days of his mourning were past, Joseph spake unto the house of Pharaoh,"], ["ona fai atu lea o Iosefa i le aiga o Farao,", "saying,"], ["o loo faapea atu,", "If now I have found grace in your eyes, speak,"], ["Afai ua outou alofa mai ia te au,", "I pray you,"], ["ia faapea ona outou fetalai ane ia Farao;", "in the ears of Pharaoh, saying,"]]},
  {num:5,words:[["Na fai mai lo'u tamā ia te au ou te tauto atu ia te ia,", "My father made me swear,"], ["ua faapea mai,", "saying,"], ["Faauta,", "Lo,"], ["o a'u nei o le a a'u oti;", "I die:"], ["o le tuugamau na ou elia mo'u i le nuu o Kanana,", "in my grave which I have digged for me in the land of Canaan,"], ["o le mea lava lea e te tanumia ai a'u;", "there shalt thou bury me. Now therefore let me go up,"], ["o lenei,", "I pray thee,"], ["se'i tuu mai ia a ou alu ae e tanu i lo'u tamā,", "and bury my father,"], ["ona ou foi mai lava lea.", "and I will come again."]]},
  {num:6,words:[["Ona fai mai lea o Farao,", "And Pharaoh said,"], ["Ina alu ae ia,", "Go up,"], ["ma tanu lou tamā,", "and bury thy father,"], ["pei ona e tauto atu ia te ia.", "according as he made thee swear."]]},
  {num:7,words:[["Ona alu ae lea o Iosefa ina ia tanu lona tamā;", "And Joseph went up to bury his father:"], ["na o ae foi faatasi ma ia o auauna uma a Farao,", "and with him went up all the servants of Pharaoh,"], ["o toeaina o lona aiga,", "the elders of his house,"], ["ma toeaina uma lava o le nuu o Aikupito;", "and all the elders of the land of Egypt,"]]},
  {num:8,words:[["atoa ma le aiga uma o Iosefa,", "And all the house of Joseph,"], ["ma ona uso,", "and his brethren,"], ["ma le aiga o lona tamā,", "and his father's house: only their little ones,"], ["na o tama iti,", "and their flocks,"], ["ma lafu mamoe ma povi,", "and their herds,"], ["na tuua ia e i latou i le nuu o Kosena.", "they left in the land of Goshen."]]},
  {num:9,words:[["Na o ae foi faatasi ma ia o nofoa faataavalevale ma e tietie i solofanua,", "And there went up with him both chariots and horsemen:"], ["sa matuā toatele lava.", "and it was a very great company."]]},
  {num:10,words:[["Ua latou oo i le fale e soli ai saito o Atatu,", "And they came to the threshingfloor of Atad,"], ["o loo i tala atu i Ioritana;", "which is beyond Jordan,"], ["ona latou taufaitagitu'i ai lea i le tagitu'i matuā tele lava;", "and there they mourned with a great and very sore lamentation:"], ["ua fai ai le faanoanoa ona o lona tamā e fitu ona aso.", "and he made a mourning for his father seven days."]]},
  {num:11,words:[["Ua iloa foi e na nonofo i le nuu o Kanana le faanoanoa i le fale e soli ai saito o Atatu,", "And when the inhabitants of the land,"], ["ona faapea ane lea o i latou,", "the Canaanites, saw the mourning in the floor of Atad,"], ["O le faanoanoa lenei o Aikupito e matuā tele;", "they said,"], ["o le mea lea ua ta'ua ai lea mea Apelamisarima,", "This is a grievous mourning to the Egyptians: wherefore the name of it was called Abel-mizraim,"], ["o loo i tala atu o Ioritana.", "which is beyond Jordan."]]},
  {num:12,words:[["Ua faia e ona atalii ia te ia, e faapei ona ia fetalai atu ia i latou.", "And his sons did unto him according as he commanded them:"]]},
  {num:13,words:[["Auā ua ave ia e ona atalii i le nuu o Kanana, ma latou tanumia o ia i le ana i le fanua o Makapelu,", "For his sons carried him into the land of Canaan,"], ["na faatauina mai e Aperaamo,", "and buried him in the cave of the field of Machpelah,"], ["atoa ma le fanua,", "which Abraham bought with the field for a possession of a buryingplace of Ephron the Hittite,"], ["e fai ma tuugamau mai ia Eferona o le sa Hetī, o loo i luma o Mamere.", "before Mamre."]]},
  {num:14,words:[["Ona foi atu lea o Iosefa i Aikupito,", "And Joseph returned into Egypt,"], ["o ia,", "he,"], ["ma ona uso,", "and his brethren,"], ["ma i latou uma o e na o ae ma ia e tanu i lona tamā,", "and all that went up with him to bury his father,"], ["ina ua uma ona tanu o lona tamā.", "after he had buried his father."]]},
  {num:15,words:[["Ua iloa e uso o Iosefa ua oti lo latou tamā,", "And when Joseph's brethren saw that their father was dead,"], ["ona faapea ai lea,", "they said,"], ["Anei e faalotoloto mai Iosefa ia i tatou,", "Joseph will peradventure hate us,"], ["ma na matuā taui mai ia te i tatou o mea leaga uma na tatou faia ia te ia.", "and will certainly requite us all the evil which we did unto him."]]},
  {num:16,words:[["Ona latou avatu lea o le feau ia te ia,", "And they sent a messenger unto Joseph,"], ["ua faapea atu,", "saying,"], ["Na poloai mai lou tamā, ina o le maliu o ia,", "Thy father did command before he died,"], ["ua faapea mai,", "saying,"]]},
  {num:17,words:[["Ia faapea ona outou fai atu ia Iosefa,", "So shall ye say unto Joseph,"], ["Ou te aioi atu ia te oe,", "Forgive, I pray thee now,"], ["ia e faamagaloina le agaleaga a ou uso ma la latou agasala,", "the trespass of thy brethren,"], ["auā na latou agaleaga atu lava ia te oe;", "and their sin;"], ["o lenei,", "for they did unto thee evil:"], ["matou te aioi atu,", "and now, we pray thee,"], ["ia e faamagaloina le agaleaga a auauna nei a le Atua o lou tamā.", "forgive the trespass of the servants of the God of thy father."], ["Ona tagi lea o Iosefa i a latou upu ia te ia;", "And Joseph wept when they spake unto him."]]},
  {num:18,words:[["ua o atu foi ona uso,", "And his brethren also went and fell down before his face;"], ["ma faapauu i ona luma,", "and they said,"], ["ma fai atu i latou ia te ia, Faauta,", "Behold,"], ["o au auauna i matou nei.", "we be thy servants."]]},
  {num:19,words:[["Ona fai mai lea o Iosefa ia te i latou,", "And Joseph said unto them,"], ["Aua ne'i outou matatau;", "Fear not:"], ["pe la o a'u o le sui o le Atua.", "for am I in the place of God?"]]},
  {num:20,words:[["A o outou,", "But as for you,"], ["na fai togafiti e outou ia leaga ai a'u;", "ye thought evil against me;"], ["a o le Atua,", "but God meant it unto good,"], ["na finagalo ia ia iu i le lelei,", "to bring to pass,"], ["ina ia oo ina faaolaina o le nuu e toatele,", "as it is this day,"], ["pei ona taunuu ai i ona po nei.", "to save much people alive."]]},
  {num:21,words:[["O lenei,", "Now therefore fear ye not:"], ["aua ne'i matatau outou;", "I will nourish you,"], ["o a'u nei ou te tausi lava ia te outou ma a outou fanau; ona faamatalaloto mai lea o ia ia te i latou,", "and your little ones. And he comforted them,"], ["ma tautala lelei mai ia te i latou.", "and spake kindly unto them."]]},
  {num:22,words:[["Sa nofo foi Iosefa i Aikupito,", "And Joseph dwelt in Egypt,"], ["o ia atoa ma le aiga o lona tamā;", "he, and his father's house:"], ["o le ola o Iosefa ua selau ma le sefulu o tausaga;", "and Joseph lived an hundred and ten years."]]},
  {num:23,words:[["sa iloa foi e Iosefa le fanau a Efaraima ua oo i le tupulaga e tolu;", "And Joseph saw Ephraim's children of the third generation:"], ["o le fanau foi a Makiro o le atalii lea o Manase na sapasapaia i luga o tulivae o Iosefa.", "the children also of Machir the son of Manasseh were brought up upon Joseph's knees."]]},
  {num:24,words:[["Ona fai atu lea o Iosefa i ona uso,", "And Joseph said unto his brethren,"], ["O a'u nei o le a a'u oti;", "I die:"], ["a o le Atua, e asiasi mai lava o ia ia te outou,", "and God will surely visit you,"], ["ma aveina ae outou ai le nuu nei i le nuu na tauto ai o ia ia Aperaamo,", "and bring you out of this land unto the land which he sware to Abraham,"], ["ma Isaako,", "to Isaac,"], ["atoa ma Iakopo.", "and to Jacob."]]},
  {num:25,words:[["Ona fai atu ai lea o Iosefa ia tauto mai le fanauga a Isaraelu,", "And Joseph took an oath of the children of Israel,"], ["ua faapea atu,", "saying,"], ["E asiasi mai lava le Atua ia te outou;", "God will surely visit you,"], ["tou te avae foi o'u ivi ai le mea nei.", "and ye shall carry up my bones from hence."]]},
  {num:26,words:[["Ona oti lea o Iosefa ina ua atoa ona tausaga e selau ma le sefulu;", "So Joseph died,"], ["na atualalaina foi o ia e i latou,", "being an hundred and ten years old: and they embalmed him,"], ["ma tuu i le atolaau i Aikupito.", "and he was put in a coffin in Egypt."]]},
];
renderVerseSet(gen_ch_50_Verses, 'gen-ch50-verses');

